export default function Screen2(props) {
  const classes = useStyles();

  const [open,toggle]=useState(false)
const[chipData,setChipData]=useState(null)

const handleAddChip=(e)=>{
  let Category=[...props.ProgramDetails.Category]
  Category.push(chipData)
  setChipData(null)
  props.updateProgram({Category})
toggle(false)
}


 
const deleteCat=(index)=>{
  let Category=[...props.ProgramDetails.Category]
  Category.splice(index,1)
  props.updateProgram({Category})
}


const setInputData=(e)=>{
  props.updateProgram({[e.target.id]:e.target.value})
}

const next=()=>{
  let {Title,Description}=props.ProgramDetails
  if((Title==null||Title=="")){
    props.updateFeedback({loading:false,snackbar:true,message:"Please enter valid Title",severity:"warning"})
  }
  else{
    if(props.location.state&&props.location.state.mode=="edit")
    props.history.goBack()
    else
    props.history.push(`${props.match.url}/add-days`,props.location.state)
  }
}
  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Create description</h2>
       
        <div className={classes.mainDiv}>
       <Grid container spacing={0}>
<Grid item xs={12}>
<CustomInput
bottomUnderline
                        labelText="Title"
                        id="Title"
                      
                      
        inputProps={{
        
          value:props.ProgramDetails.Title,
          onChange:setInputData,
            placeholder:"Program title"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
<br/>
<Grid item xs={12} style={{marginTop:20}}>
<CustomInput
bottomUnderline
                        labelText="Description"
                        id="Description"
                        multiline
                        rows={2}
        inputProps={{
          style:{marginTop:7},
         value:props.ProgramDetails.Description,
         onChange:setInputData,
            placeholder:"(Optional) Write a brief about your program"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>

       </Grid>
        </div>
      </Content>
      <Footer actionButton>
     
        <Button
        onClick={next}
          variant="contained"
          
          fullWidth
          size="lg"
          disabled={props.ProgramDetails.Title==null||props.ProgramDetails.Title.length<2}
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      
      </Footer>
    </Container>
  );
}
