function Screen2(props) {
  const classes = useStyles();
  const [data, setData] = useState({
    BannerImage: null,
  });
  console.log(props.Profile)
  useEffect(() => {
    props.getSpecificPublicProgram(props.id).then((data) => {
      setData({ ...data, name:data.createdBy.name ,profilePic: data.createdBy.profilePic,});
    },(err)=>props.history.goBack());
  }, []);

  const BuyProgram=()=>{
    createOrder({ 
      Program:{...data,createdBy:data.createdBy._id},
        
    
    }).then(res=>props.history.push("/athlete"))
  }

  const onEdit=()=>{

    store.dispatch({ type:"EDIT_ID",payload:{editId:props.id}})
    props.history.push("/edit-program")
  }
  return (
    <Container>
        <Header />
      <Content>
        <div style={{padding:"25px 25px 0px 25px"}}>
        <div
          className={classes.banner}
          style={{
            backgroundImage: data.BannerImage
              ? `url(${data.BannerImage})`
              : `url(${require("assets/img/fitness.jpg")})`,
            backgroundSize: "cover",
          }}
        >
         
         
     
        </div>
</div>
        <div className={classes.mainDiv}>
          <div className={classes.title}>{data.Title}</div>
          <div className={classes.description}>{data.Description}</div>
          <Divider style={{width: "100%",marginTop:3,marginBottom:10,backgroundColor:"#ECEEEF"}}/>
          <div className={classes.title} style={{marginTop:10,marginBottom:15}}>Program details</div>

<div className={classes.detail}>Duration: <span className={classes.dark}>4 weeks</span></div>
<div className={classes.detail}>Type: <span className={classes.dark}>{data.PaymentType}</span></div>
<div className={classes.detail}>Price: <span className={classes.dark}>${data.Price}</span></div>
         
<Divider style={{width: "100%",marginTop:3,marginBottom:20,backgroundColor:"#ECEEEF"}}/>
<Grid item xs={12}>
              <span className={classes.title}>Program by</span>
              <div style={{display: "flex",flexDirection:"row",flex:1,  marginTop:5}}>
            <Avatar  className={classes.AvatarImage} imgProps={{style:{width: "100%",height: "auto",objectFit: "fill"}}} src={data.createdBy?data.createdBy.profilePic:""}/>
              <div className={classes.secondary} style={{dipslay:"flex",flex:1,lineHeight:"20px",flexDirection:"column",marginLeft:15,alignItems:"center",textTransform:"capitalize"}}>
                {data.createdBy
                  ? data.createdBy.name
                  : "N/A"}

                  <div style={{color:"#007EA0",lineHeight:"20px"}}>View profile</div>
              </div>
              </div>
            </Grid>
            <Divider style={{width: "100%",marginTop:15,marginBottom:20,backgroundColor:"#ECEEEF"}}/>
        </div>
      </Content>
      <Footer actionButton>
       
    
         <Button
        onClick={() =>props.history.push(`/chat/dt/${data.createdBy._id}`,{request:{...data}})}
           variant="contained"
           fullWidth
           size="lg"
           bold
        
         >
           Request
         </Button>
    

   </Footer>

    </Container>
  );
}

export default connect(null, { getSpecificPublicProgram })(Screen2);
