export default function Screen2(props) {
  const classes = useStyles();
const [bio,setBio]=useState(props.Profile.bio)
const [val,setVal]=useState(null)
const divRref = useRef(null);
const changeBio=(e)=>{

  setBio(e.target.value)
}


const handleChange=(value,index)=>{
  let arr=[...props.Profile.links]

  if(value){
    arr[index]=value
  }
  else
  {arr.splice(index,1)}
  props.updateInfo({links:arr})
}

const addNewLink=(e)=>{
let arr=[...props.Profile.links]
if(e.target.value){
  arr.push(e.target.value)
  props.updateInfo({links:arr})
  setVal("")
}
}

const handleNext=()=>{
  props.updateProfile({...props.Profile,healthGoals:bio}).then((res)=>
  props.history.replace('/profile/profile-preview')
  )
}

const uploadProfilePic=(e)=>{
  props.updateFeedback({loading:true})
  handleuploadImage(e).then((res)=>{
props.updateProfile({profilePic:res.data.Location})
props.updateFeedback({loading:false})
  },rej=>{
if(rej=="size")
return props.updateFeedback({loading:false,snackbar:true,message:"Image size should be less than 5 mb",severity:"warning"})
else
return props.updateFeedback({loading:false,snackbar:true,message:"Error in uploading image please try again later",severity:"warning"})
  })
}

const uploadBanner=(e)=>{
  props.updateFeedback({loading:true})
  handleuploadImage(e).then((res)=>{
props.updateProfile({banner:res.data.Location})
props.updateFeedback({loading:false})
  },rej=>{
if(rej=="size")
return props.updateFeedback({loading:false,snackbar:true,message:"Image size should be less than 5 mb",severity:"warning"})
else
return props.updateFeedback({loading:false,snackbar:true,message:"Error in uploading image please try again later",severity:"warning"})
  })
}


  return (
    <Container>
  <Navbar style={{ backgroundColor: "rgba(0,0,0,0)" }} />

      <Content>
       
      <div className={classes.Banner} style={{backgroundImage:`url(${props.Profile.banner})`,backgroundSize:"cover"}}>
            {<Camera className={classes.bannerIcon} onClick={()=>document.getElementById("banner").click()} />}
            <input type="file" id="banner" onChange={uploadBanner} style={{display:"none"}}/>
            
            <input type="file" id="profile" onChange={uploadProfilePic} style={{display:"none"}}/>
       <div
        overlap="circle"
        className={classes.Avatar}
      
      >
          <Camera  onClick={()=>document.getElementById("banner").click()} style={{position: "absolute",top:23,left:23,zIndex:200,fontSize:30,color:"white"}} />

            <Avatar className={classes.AvatarImage}  onClick={()=>document.getElementById("profile").click()}  src={props.Profile.profilePic?props.Profile.profilePic:ProfilePic}>
          

            </Avatar>
            </div>
        </div>


        <div className={classes.mainDiv}>
       <Grid container spacing={0}>
         <Grid item xs={12}>
            <ListItem 
        title="Username"
        value={props.Profile.name}
        noIcon
        onClick={()=>props.history.push(`/profile/edit-name`)}
        />

       
         <ListItem 
         style={{paddingBottom:0}}
        title="Goals"
        value="******"
        noIcon
        bordered
        component={
          <div style={{marginTop:0,width: "100%"}}><CustomInput
          bottomUnderline
                        id="float"
        inputProps={{
          style:{border:"none"},
            placeholder:"Small brief about yourself",
           defaultValue:props.Profile.healthGoals,
           onChange:changeBio
        }}
        multiline
        rows={2}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      /></div>
        }
        />
       
       <ListItem 
        title="Location"
        value={getLocation(props.Profile.location)}
        onClick={()=>props.history.push(`/profile/location/edit`)}
        noIcon
        borderedBoth/>
           </Grid>









           <Grid item xs={12} style={{marginTop:10}} >
            <Accordion className={classes.accordian} onChange={()=>setTimeout(()=>divRref.current.scrollIntoView({ behavior: 'smooth' }),300)   } ref={divRref}>
        <AccordionSummary
        className={classes.accordianSummary}
          expandIcon={<ExpandMoreIcon color={"primary"} />}
          aria-controls="panel1a-content"
          id="panel1a-header"
        >
          <Typography className={classes.title2}>Private information</Typography>
        </AccordionSummary>
        <AccordionDetails className={classes.accordianContent}>
        <Grid container spacing={0}>
         <Grid item xs={12}>
            <ListItem 
        title="Email"
        noIcon
        value={props.Profile.email?props.Profile.email:"N/A"}
        onClick={()=>props.history.push(`/profile/edit-phone-email/email`)}
        />
        <ListItem 
        title="Phone"
        noIcon
        value={props.Profile.phone?props.Profile.phone:"N/A"}
        onClick={()=>props.history.push(`/profile/edit-phone-email/phone`)}
        bordered/>
         <ListItem 
         noIcon
        title="Gender"
        value={props.Profile.gender?props.Profile.gender:"N/A"}
        onClick={()=>props.history.push(`/profile/update-gender`)}
        bordered/>
         <ListItem 
         noIcon
        title="Birthday"
        value={props.Profile.DOB?moment(props.Profile.DOB).format('ll'):""}
        onClick={()=>props.history.push(`/profile/edit-dob`)}
        bordered/>
        </Grid>
        </Grid>
        </AccordionDetails>
      </Accordion>
</Grid>
       </Grid>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Save
        </Button>
      </Footer>
    </Container>
  );
}
