export default function Screen2(props) {
  const classes = useStyles();

  const [open,toggle]=useState(false)
const[chipData,setChipData]=useState(null)
const[validation,setValidation]=useState({
  programDescription:true,

  workoutCalender:false,
  cover:true
})

useEffect(()=>{

let validations={...validation}

  if(props.ProgramDetails.Title){
validations.programDescription=false
  }
else
{validations.programDescription=true}

let exist=props.ProgramDetails.ExercisePlan.map((week,index)=>{

let validdays=week.filter(day=>day.Exercise.length>0)

if(validdays.length==0){
  return false
}
else
return true
})

console.log(exist)

if(exist.findIndex((existdata=>existdata))>-1){
  validations.workoutCalender=false
}
else
{validations.workoutCalender=true}

if(props.ProgramDetails.BannerImage){
  validations.cover=false
}
else
validations.cover=true


setValidation(validations)

},[props.ProgramDetails])




const next=()=>{

 if(props.mode=="editSend"){
   props.setEdited()
   return(props.history.goBack())
 }
    if (props.editMode) {

let IsDraft=(validation.programDescription||validation.workoutCalender||validation.cover)?true:false

        props.saveProgram({...props.ProgramDetails,IsDraft:IsDraft}).then((program) => {
          props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Program updated succesfully",
            severity: "success",
          });
          props.history.push("/instructor");
        });
      
      } 
}

const validateData=()=>{
  if (props.editMode) {
    let IsDraft=(validation.programDescription||validation.workoutCalender||validation.cover)?true:false
    if(IsDraft){
      toggle(true)
    }
    else
    next()
  }
  else
  toggle(true)
}

  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>{props.ProgramDetails.IsDraft?"Un-completed":"Edit program"}</h2>
       <label className={classes.label}>{props.ProgramDetails.IsDraft?<>Fill the following to complete building<br/> your program.</>:<>Navigate and select part of your<br/> program you want to edit.</> }</label>
        <div className={classes.mainDiv}>
     
<div className={classes.Tabs}>
<ButtonBase onClick={()=>props.history.push(`${props.match.url}/`,{mode:"edit"})} className={classes.Tab}>
  <Description className={classes.icon}/>  <div className={classes.TabInside}>Program Description{validation.programDescription&&<ErrorOutlineIcon/>}</div>
</ButtonBase>


<ButtonBase className={classes.Tab} onClick={()=>props.history.push(`${props.match.url}/add-days`,{mode:"edit"})}>
  <CallanderIcon className={classes.icon}/><div className={classes.TabInside}>  Workout calander{validation.workoutCalender&&<ErrorOutlineIcon/>}</div>
</ButtonBase>


<ButtonBase className={classes.Tab} onClick={()=>props.history.push(`${props.match.url}/create-diet`,{mode:"edit"})}>
  <DietIcon className={classes.icon}/> <div className={classes.TabInside}> Diet plan</div>
</ButtonBase>


<ButtonBase className={classes.Tab} onClick={()=>props.history.push(`${props.match.url}/upload-banner`,{mode:"edit"})}>
  <Camera className={classes.icon}/> <div className={classes.TabInside}>Cover image{validation.cover&&<ErrorOutlineIcon/>}</div>
</ButtonBase>


<ButtonBase className={classes.Tab} onClick={()=>props.history.push(`${props.match.url}/setup-payment`,{mode:"edit"})}>
  <Money className={classes.icon}/><div className={classes.TabInside}>  Payment method</div>
</ButtonBase>

</div>

<ActionModal
open={open}
title={props.editMode?"Save as draft ?":"Please note !"}
message={props.editMode?"Your program will be saved as draft until you satisfy marked components":"This edit will be only for the client your sending to. It will not effect the original program."}
handleClose={()=>toggle(false)}
continue={next}
/>

        </div>
      </Content>
      <Footer actionButton>
     
        <Button
        onClick={validateData}
          variant="contained"
          
          fullWidth
          size="lg"
          disabled={props.ProgramDetails.Title==null||props.ProgramDetails.Title.length<2}
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Save
        </Button>
      
      </Footer>
    </Container>
  );
}
