import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"
import Search from "assets/svg/SearchHeart"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {

    width: "100%",
    display: "flex",
    flexDirection: "row",
  marginTop:20,
  fontFamily: "Lato",
  boxSizing: "border-box",




  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
alignItems:"center",
justifyContent:"center",
  }
,
  content:{
      
      marginLeft:15
  },


  childDiv:{
    padding:25,
    borderRadius:22,
    display:"flex",
    flexDirection:"row",
   
   
    
    
  },

 icon:{
fontSize: 60
 },
  title:{ 
     
    color: "#172A44",
      fontWeight:"bold",
      fontSize:16,
    display: "inline"
    },

  images:{
    display: "flex",
     width: "100%",
     flexDirection:"row",
    
  }
,

image:{
 width:"50%",
 
marginTop:10,
borderRadius: "12px",



},
inside:{
  width:"90%",

paddingTop:"80%",
  borderRadius: "12px",
   background:"black",
   
},
time:{
fontSize: 10,
marginLeft:5,
color: "#172A44",
}
,
  subTitle:{
    fontWeight: "normal",
    fontFamily:"Proxima Nova",
    fontStyle:"normal",
    fontSize: 14,
    marginTop:10,
    lineHeight: "18px",
  
    color: "#707C97"
  },
  small:{
    width:"auto"
  }

}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images,
IconAv,

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
  
})
  
const childDiv = classNames({
    [classes.childDiv]: true,
    [classes.white]:white
})
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  
      <div className={mainDiv}>
          <div className={childDiv}>
          <div className={classes.avatar}>

        {IconAv}
        </div>
        <div className={classes.content}>
            <div className={classes.title}>
           {Title} <span className={classes.time}>{Time}</span>

            </div>
            <div className={classes.subTitle}>
            {Text}
            </div>

             <div className={classes.images}>
               {Images.map(item =>( <div className={classes.image}>
<div className={classes.inside}
style={{backgroundImage: "url(" + item + ")",backgroundSize:"cover"}}
></div>
              </div>))}
             
              
            </div> 
        </div>
        </div>
</div>


 
  );
});


export default AnnouncCard;
