import React, { Component ,useState} from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  }
}));

export default function Screen2(props) {
  const [password,setPassword]=useState(null)
  const [passwordConfirm,setPasswordConfirm]=useState(null)
  const classes = useStyles();
const onSubmit=()=>{
  props.updateFeedback({loading:true})
  axios.patch(`${api.protocol}${api.baseUrl}${api.changePassword}`,{password:password,token:props.data.token}).then((res)=>{
  
     props.updateFeedback({loading:false,snackbar:true,message:"Password reset completed",severity:"success"})
    props.history.push(`/`)
  }).catch((err)=>{
  
    return props.updateFeedback({loading:false,snackbar:true,message:"Unauthorized access",severity:"error"})
  })
}
  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Create new password</h2>
        <p className={classes.secondary}>Choose strong password that you can remember</p>
        <div className={classes.mainDiv}>
         
        <CustomInput
                      labelText="Choose Password"
                      id="float"
        inputProps={{
            type: "password",
            value: password,
            onChange:(e)=>setPassword(e.target.value)
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                       <CustomInput
                      labelText="Confirm Password"
                      id="float"
      inputProps={{
          type: "password",
          
          value: passwordConfirm,
          onChange:(e)=>setPasswordConfirm(e.target.value)
      }}
                      formControlProps={{
                        fullWidth: true,
                        
                      }}
                    />
        </div>
      </Content>
      <Footer actionButton>
        <Button
        
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
          onClick={onSubmit}
        >
          Submit
        </Button>
      </Footer>
    </Container>
  );
}
