import React, { Component,useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import {validateEmail,validatePassword,validatePhone,validateName} from "utils/validator"
import {isPossiblePhoneNumber} from "react-phone-number-input"
import 'react-phone-input-2/lib/style.css'
import DateFnsUtils from '@date-io/date-fns';
import VisibilityIcon from '@material-ui/icons/VisibilityOutlined';
import VisibilityOffIcon from '@material-ui/icons/VisibilityOffOutlined'
import 'date-fns';
import { FastfoodOutlined } from "@material-ui/icons";
import { socketConnection } from "store/actions/common";
import {
  MuiPickersUtilsProvider,
  KeyboardTimePicker,
  KeyboardDatePicker,
} from '@material-ui/pickers';
import InputAdornment from "@material-ui/core/InputAdornment";

import CalendarTodayIcon from '@material-ui/icons/CalendarToday';
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:24,
    marginBottom: 25,
    marginTop:2,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:0,
    flexDirection: "column",

    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:"normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,

  },
  icon:{
      fontSize:45,
      marginRight:25
  },
  forgetPassword: {
    width: "100%",
    display: "flex",
    flexDirection: "row",
    alignItems: "flex-end",
    justifyContent: "flex-end",
    fontFamily: "Proxima Nova",
    color: "rgb(0, 126, 160)",
    fontWeight: "bold",
    fontSize: "14px",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [showPass,setShowPass]=useState(false)
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authType, setType] = useState(0);
  const [phone, setPhone] = useState("");


const setMobileOrEmail=(e)=>{
  if(isPossiblePhoneNumber("+"+e.target.value))
{
    setType(0)
    setPhone(e.target.value)

}

if( validateEmail(e.target.value)){
    setType(1)
    setEmail(e.target.value)
 
}
 

}


const VerifyAccount = () => {
 
    props.updateFeedback({ loading: true });
    if (authType == 0) {
      if (validatePhone(phone) && validatePassword(password)) {
        axios
          .post(`${api.protocol}${api.baseUrl}${api.userLogin}`, {
            phone,
            password,
            email,
          })
          .then((response) => {
            setTimeout(() => socketConnection(), 1000);
            props.updateFeedback({
              loading: false,
              snackbar: true,
              message: "Login successfuly",
              severity: "success",
            });
            let {
              category,
              name,
              bio,
              type,
              DOB,
              privatePlan,
              profilePic,
              location,
              email,
              links,
              phone,
              token,
              _id,
            } = response.data.userData;


            if(props.history.location.state&&props.history.location.state.return)
            props.history.push(props.history.location.state.return)

            axios.defaults.headers.common["Authorization"] =
              response.data.token;
            localStorage.setItem("token", response.data.token);

            props.initProfile({
              _id,
              category,
              name,
              bio,
              type,
              DOB,
              privatePlan,
              profilePic,
              location,
              links,
              email,
              phone,
              token: response.data.token,
              password: "",
              ...response.data.userData,
            });
          
            // else
            // props.history.push(
            //   response.data.userData == "Athlete" ? "/athlete" : "/instructor"
            // );
          })
          .catch((error) => {
            if (error.response && error.response.status === 404)
              return props.updateFeedback({
                loading: false,
                snackbar: true,
                message: "User with provided email or phone doesn't exist",
                severity: "error",
              });
            if (error.response && error.response.status === 401)
              return props.updateFeedback({
                loading: false,
                snackbar: true,
                message: "Invalid Password",
                severity: "error",
              });
          });
      } else {
        if (!validatePhone(phone))
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Please enter a valid phone number!",
            severity: "warning",
          });
        if (!validatePassword(password))
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Length of password must be greater than or equal to 6",
            severity: "warning",
          });
      }
    } else {
      if (validateEmail(email) && validatePassword(password)) {
        axios
          .post(`${api.protocol}${api.baseUrl}${api.userLogin}`, {
            phone,
            password,
            email,
          })
          .then((response) => {
            setTimeout(() => socketConnection(), 1000);
            props.updateFeedback({
              loading: false,
              snackbar: true,
              message: "Login successfuly",
              severity: "success",
            });
            let {
              _id,
              category,
              name,
              bio,
              type,
              DOB,
              privatePlan,
              profilePic,
              location,
              links,
              email,
              phone,
            } = response.data.userData;
            if(props.history.location.state&&props.history.location.state.return)
            { props.history.push(props.history.location.state.return)}


            axios.defaults.headers.common["Authorization"] =
              response.data.token;
            localStorage.setItem("token", response.data.token);

            props.initProfile({
              _id,
              category,
              name,
              bio,
              type,
              DOB,
              privatePlan,
              profilePic,
              location,
              links,
              email,
              token: response.data.token,
              phone,
              password: "",
              ...response.data.userData,
            });
         
            // else
            // props.history.push(
            //   response.data.userData == "Athlete" ? "/athlete" : "/instructor"
            // );
          })
          .catch((error) => {
            if (error.response && error.response.status === 404)
              return props.updateFeedback({
                loading: false,
                snackbar: true,
                message: "User with provided email or phone doesn't exist",
                severity: "error",
              });
            if (error.response && error.response.status === 401)
              return props.updateFeedback({
                loading: false,
                snackbar: true,
                message: "Invalid Password",
                severity: "error",
              });
          });
      } else {
        if (!validateEmail(email))
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Please enter a valid email!",
            severity: "warning",
          });
        if (!validatePassword(password))
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Length of password must be greater than or equal to 6",
            severity: "warning",
          });
      }
    }
  };



  return (
    <MuiPickersUtilsProvider utils={DateFnsUtils}>
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>Sign in </span>
       
        <div className={classes.mainDiv}>
    
        <CustomInput

                        labelText="Email or mobile"
                        id="float"
                        placeholder="+91-88###-####"
                       
                        bottomUnderline
                       
        inputProps={{ 
    
          onBlur:setMobileOrEmail,
            placeholder:"Your email or phone number (+01 )",
          key:"1",
       }}
                        formControlProps={{
                          fullWidth: true
                        }}
                      />



<CustomInput
                      labelText="Password"
                      
                      bottomUnderline
        inputProps={{
    
         onChange:(e)=>setPassword(e.target.value),
         placeholder:"your password",
         type:!showPass?"password":"text",
        endAdornment:!showPass?<VisibilityOffIcon onClick={()=>setShowPass(true)}/>:<VisibilityIcon onClick={()=>setShowPass(false)}/>
          
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />



<div
            className={classes.forgetPassword}
            onClick={() => props.history.push("/resetpassword",props.location.state
            )}
          >
            Forget Password ?
          </div>
        </div>
      
      </Content>
      <Footer actionButton>
        <Button
        //  onClick={()=>props.history.push("/onboarding/account-verification")}
        onClick={VerifyAccount}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={(!email||!phone)&&password.length<8}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Sign In
        </Button>
      </Footer>
    </Container>
    </MuiPickersUtilsProvider>
  );
}


