import React, { Component } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Navbar2";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Grid from "@material-ui/core/Grid";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Earth from "assets/svg/Earth";
import LockOutlinedIcon from "@material-ui/icons/LockOutlined";
import Athlete from "assets/svg/WeightLifting";
import ReactPlayer from "react-player";
import InputBase from "@material-ui/core/InputBase";
import InfoBox from "components/InfoBox";
import BottomNav from "components/BottomNav";
import NumberSelector from "components/CustomTabs/NumberTabs";
import VideoThumbnail from "react-video-thumbnail";
import NoteAddOutlinedIcon from "@material-ui/icons/NoteAddOutlined";
import AddIcon from "@material-ui/icons/Add";
import { withStyles } from "@material-ui/styles";
import ClickAwayListener from "@material-ui/core/ClickAwayListener";
import Dialogue from "components/Dialogue/videoUpload"
import axios from "utils/axios"
import api from "utils/api"
import { Video } from 'video-metadata-thumbnails';
const styles = (theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 24,
    marginBottom: 5,
    marginTop: 2,
color:"white",
textTransform: "capitalize",
  },
  mainDiv: {
    width: "100vw",
    height: "100vh",
    background: "#000",

    position: "relative",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 1,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
  },
  bottomText: {
    marginTop: "20px",
  },
  bottom: {
    position: "absolute",
    bottom: 0,
    paddingBottom: 30,
    width: "100vw",
    background:
      "linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, #000000 100%)",

    backdropFilter: "blur(2px)",
  },
  Footer: {
    margin: "0px 20px 20px 20px",
  },
  Inputbase: {
    fontSize: 16,

lineHeight: "22px",
   
    letterSpacing: "1px",
textAlign: "center",
    fontColor: "#fff",
    color: "#fff",
    fontFamily: "Proxima Nova",
    textAlign: "center",
   
  },
  inputDiv: {
    width: "100%",
    
  },
});
class VideoExercise extends Component {
  state = {
    title: "",
    reps: 10,
    sets: 3,
    note: null,
    rest: 30,
    banner:null,
    visibleNumbers: false,
    selected: null,
    uploadModal:false,
    uploadPercentage:0,
    urlFile:null,
    showContent:true
  };

  handleClickAway = () => {
    this.setState({ showContent: false });
  };

 
  componentDidMount=()=>{
      if(this.props.data&&this.props.data.file)
this.setState({...this.props.data.file.otherDetails})
else
this.props.history.goBack()
  }

  render() {
    const { classes } = this.props;
    return (
      
      <Container>
        <Content flex>
          <Header
          viewMode
        
          
 
          />
          <div className={classes.mainDiv} onClick={() =>this.setState({showContent:!this.state.showContent})}>
            
            <ReactPlayer
              playing={true}
              loop={true}
              autoPlay
              url={this.state.url}
              width="100vw"
              height="100vh"
            ></ReactPlayer>
            {/* <VideoThumbnail
videoUrl={require("assets/sampleVideo/Poolgames.mp4")}
thumbnailHandler={(thumbnail) => console.log(thumbnail,"thumbnail generated")}

/> */}
            <ClickAwayListener onClickAway={this.handleClickAway}>
              <>
            {this.state.showContent &&   <div className={classes.bottom} onClick={(e) =>e.stopPropagation()}>
             
                  <div className={classes.inputDiv}>
                    <center className={classes.title}>{this.state.title}</center>
                    <p className={classes.Inputbase}>
                   { this.state.note}
                    </p>
                   
                  </div>
              

               

              
                <br />
                <Grid
                  container
                  direction="row"
                  justify="center"
                  alignItems="center"
                
                >
                  <Grid item xs={3}>
                  <center>
                    <InfoBox
                      title={this.state.sets ? this.state.sets :  "-"}
                      subTitle={"sets"}
                   
                    />
                    </center>
                  </Grid>

                  <Grid item xs={3}>
                    <center>
                    <InfoBox
                      title={this.state.reps ? this.state.reps : "-"}
                      subTitle={"reps"}
                   
                    />
                    </center>
                  </Grid>
                  <Grid item xs={3}>
                  <center>
                    <InfoBox
                      title={
                        this.state.rest ? this.state.rest + "s" :  "-"
                      }
                      subTitle={"rest"}
                
                    />
                      </center>
                  </Grid>
                
                </Grid>
              </div>  }
              </>
            </ClickAwayListener>
          </div>
        </Content>
      </Container>
    );
   
  }
}

export default withStyles(styles)(VideoExercise);
