import React, { Component } from 'react'
import { Router, Route, Switch,Redirect } from "react-router-dom";
import ProfilePage from "../Screens/ClientViewInstructor/profile.js"
import AddDays from "../Screens/ClientViewInstructor/Calender"
import AddExercise from "../Screens/createProgram/AddExercise"
import SelectExercise from "../Screens/createProgram/SelectExercise"
import HealthInfo from "../Screens/ClientViewInstructor/healthInformation"
import CreateDiet from "../Screens/ClientViewInstructor/DietPlan"
import BodyImages from "../Screens/ClientViewInstructor/BodyImages"
import SelectUploadType from "../Screens/createProgram/SelectUploadType"
import FiggsLibrary from "./FiggsLibrary"
import ExerciseView from "../Screens/common/ExerciseView"
import {updateFeedback} from "../store/actions/feedback"
import {connect} from "react-redux"
import {getClientsSpecific,updateProgram,saveProgram} from "../store/actions/clientExercise"
class Onboarding extends Component {
    state={
        currentWeek:0,
        currentDay:0,
        file:null,
        fileObject:null,
        currentExercise:0
        
        
            }
    componentDidMount() {
        this.props.getClientsSpecific(this.props.match.params.id)
    }
    addWorkout=(data)=>{
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise.push(data)
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.push(`${this.props.match.url}/workoutCalender`)
    }


    addExercises=(data)=>{
        console.log(data)
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise=[...program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise,...data]
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.push(`${this.props.match.url}/workoutCalender`)
    }
    editExercise=(data)=>{
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]=data
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/workoutCalender`)
    }

    ViewExercise=(index)=>{
        this.setState({currentExercise:index})
        this.props.history.push(`${this.props.match.url}/edit-exercise`)
    }
    render() {
        return (
            <div>
            
                   <Route exact  path={`${this.props.match.url}/`} render={()=><ProfilePage {...this.props}/>} />
                   <Route exact  path={`${this.props.match.url}/bodyimages`} render={()=><BodyImages {...this.props}/>} />
                   <Route exact path={`${this.props.match.url}/healthinfo`} render={()=><HealthInfo {...this.props}/>} />
                   <Route exact path={`${this.props.match.url}/exercise-view`} render={()=><AddExercise {...this.props}  setState={(data)=>this.setState(data)} {...this.state}/>} />
                   <Route exact  path={`${this.props.match.url}/workoutCalender`} render={()=><AddDays {...this.props} ViewExercise={this.ViewExercise} setState={(data)=>this.setState(data)} {...this.state} custom/>}/>
                   <Route exact  path={`${this.props.match.path}/edit-exercise`} render={()=><AddExercise {...this.props} {...this.state} setState={(data)=>this.setState(data)} data={this.props.ProgramDetails.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]} editMode={true} editExercise={this.editExercise}/>}  />

                   <Route exact  path={`${this.props.match.url}/add-exercise`} render={()=><AddExercise {...this.props} file={this.state.file} setState={(data)=>this.setState(data)} fileObject={this.state.fileObject} handleWorkoutSuccess={this.addWorkout}/> } />
                   <Route exact  path={`${this.props.match.url}/diet`} render={()=><CreateDiet {...this.props}/>} />
                   <Route exact  path={`${this.props.match.url}/select-type`} render={()=><SelectUploadType {...this.props} setState={(data)=>this.setState(data)}/>} />
                   <Route    path={`${this.props.match.url}/library`} render={(props)=><FiggsLibrary {...props} addExercises={this.addExercises} selectionMode />} />
                  
            </div>
        )
    }
}
const mapStateToProps =(state) => {
    return {
        ProgramDetails:{...state.ProgramList.clientData.Program},
        clientData:state.ProgramList.clientData,
        Profile:state.Profile
    }
}

export default connect(mapStateToProps,{getClientsSpecific,updateProgram,saveProgram,updateFeedback})(Onboarding)