import React from "react";
import {useEffect} from "react"
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"
import Button from "components/CustomButtons/Button.js"
import Image from "assets/img/fitness.jpg"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",
    display: "flex",
    flexDirection: "row",
 
  fontFamily: "Proxima Nova",
  boxSizing: "border-box",

paddingTop:15,
paddingBottom:15,
borderRadius:10,

  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
  }
,
  content:{
      width: "100%",
      marginLeft:15
  },



 icon:{
fontSize: 60
 },
  title:{ 
     textTransform: "capitalize",
    color: "#172A44",
      fontWeight:"bold",
      fontSize:16,
    display: "inline",
    lineHeight: "24px"
    },

  images:{
    display: "flex",
     width: "100%",
     flexDirection:"row",
    
  }
,

image:{
 width:"50%",
 
marginTop:10,
borderRadius: "12px",



},
inside:{
  width:"90%",

paddingTop:"80%",
  borderRadius: "12px",
   background:"black",
   
},
text:{
fontWeight:"normal",
lineHeight: "0px",
textTransform:"lowercase",
}
,
  subTitle:{
    fontWeight: "normal",
    fontFamily:"Proxima Nova",
    fontStyle:"normal",
    fontSize: 14,
    
    lineHeight: "22px",
  
    color: "#172A44"
  },
  small:{
    width:"auto"
  },
  time:{
     
      fontFamily:"Proxima Nova",
      fontSize: 12,
      color:"rgba(23, 42, 68, 0.5)",
      marginTop:5
  },
  button:{
     marginBottom:15,
      width:"100%"
  },
  avatar: {
      paddingRight:10
  },
  textPrimary:{
      fontWeight:"bold",
      color:"#007EA0"
  },
  dollar:{
      fontWeight:800,
      color:"#007EA0",
      fontSize:18,
      marginTop:10
  },
  PriceCardContainer:{
    display:"flex",
    flexDirection: "row",
    marginTop:5

  },
  ImageContainer:{
  
    flex:2,
    padding:5
  
  },
  DetailsContainer:{
    flex:4,
  display: "flex",
  flexDirection: "column",
  justifyContent:"space-between",
  padding:5,
  paddingTop:10,
  paddingBottom:10
  },
  Image:{
    paddingBottom:"66%",
    width:"100%",
    height:"auto",
    
    background:"grey",
    borderRadius:12
  },
  ProgramTitle:{
fontWeight:"bold",
fontSize:16,
color:"#172A44"
  },
  Price:{
    fontSize:16,
    color:"#172A44"
  }

}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images,
IconAv,
avatar,
Price,
ButtonText,
ImportantText

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
    [classes.white]:white
})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })

 
  
  return (
  <div style={{borderBottom:"0.5px solid #DDDDDD"}}>
      <div className={mainDiv}  onClick={props.onClick}>
          <div className={classes.avatar}>

        <Avatar src={avatar} ></Avatar>
        </div>
        <div className={classes.content}>
            <div className={classes.title}>
           {Title} <span className={classes.text}>{Text}</span>
           {/* <span className={classes.textPrimary}>{ImportantText}</span> */}
            </div>
           
          
            <div className={classes.time}>
          {Time}
            </div>
          <div className={classes.PriceCardContainer}>

            <div className={classes.ImageContainer}>
<div className={classes.Image} style={{backgroundImage:props.BannerImage?`url(${props.details.Program.BannerImage})`:`url(${Image})`,backgroundSize: "cover"}}>

</div>
            </div>

            <div className={classes.DetailsContainer}> 
            <span className={classes.ProgramTitle}>{props.details.Title}</span>

<span className={classes.Price}>Price:${props.details.Program.Price}</span>

            </div>
          </div>
            {/* <div className={classes.dollar}>
                {Price}
            </div> */}
        </div>

   
</div>
{/* {ButtonText&&<div className={classes.button}>
            <Button 
            onClick={props.onClick}
            variant="contained" bold fullWidth> {ButtonText}</Button>
            </div>} */}
            
</div>

 
  );
});


export default AnnouncCard;
