import axios from "utils/axios"
import api from "utils/api"
import {store} from "store"
export const createSubscription=(programId)=>{
    return new Promise((resolve, reject)=>{

        store.dispatch({ type:"UPDATE_FEED", payload: {loading:true} })
        axios.post(`${api.protocol}${api.baseUrl}${api.createSubscription}`,{id:programId}).then((response)=>{
            resolve(response.data.id)
            
        store.dispatch({ type:"UPDATE_FEED", payload: {loading:false} })
        }).catch((err=>{
            if(err.response.status==500)
            store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Oops caught some error! Please try again",severity:"error"} })
            if(err.response.status==501)
            store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"You have purchased this program",severity:"info"} })
            else
            store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Unauthorized access",severity:"error"} })
            reject(err)}))
    })

}

