import React, { Component,useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Typography from "@material-ui/core/Typography"

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';

import ProfileImg from "assets/img/screens/profile.png"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import Grid from "@material-ui/core/Grid"
import Chip from "@material-ui/core/Chip"
import Avatar from "@material-ui/core/Avatar"
import Camera from "assets/svg/Camera"

import {handleuploadImage} from "utils/uploader"
import DateFnsUtils from '@date-io/date-fns';
import 'date-fns';
import MomentUtils from '@date-io/moment';
import {
  MuiPickersUtilsProvider,
  KeyboardTimePicker,
  KeyboardDatePicker,
} from '@material-ui/pickers';
import InputAdornment from "@material-ui/core/InputAdornment";
import IconButton from "@material-ui/core/IconButton";
import CalendarTodayIcon from '@material-ui/icons/CalendarToday';
import 'react-phone-input-2/lib/style.css'
import CancelIcon from '@material-ui/icons/Cancel';
import AddIcon from '@material-ui/icons/Add';
import PublishIcon from '@material-ui/icons/Publish';
import AddFolder from "assets/svg/addFolder"
import AttachmentIcon from '@material-ui/icons/Attachment';
const useStyles = makeStyles((theme) => ({
 
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
paddingTop:10,
color: "#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
 
    padding: 25,
    paddingTop:5,
   

    fontFamily: "Proxima Nova",
  },
 
 

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontFamily: "Proxima Nova",
   paddingLeft:3,
       fontWeight: "bold",
       fontSize: "16px",
       lineHeight: "38px",
       color: "#172A44"
  },
  
 

  icon:{
position: "absolute",

top:0, 
right:"10vw"
  },
 
  Avatar:{
      position:"absolute",
      bottom:-25,
      width:60,
      height:60,
      left:30
  },
 
  label:{
    fontFamily:"Proxima Nova",
fontSize:"14px",
padding:25,
color: "#007EA0",
display:"flex",
flexDirection:"row",
alignItems:"center",

  },
  labelBold:{
    fontFamily:"Proxima Nova",
    fontSize:"16px",
    color:"#172A44"
  }
}));

export default function Screen2(props) {

  const [editMode,setEditMode] = useState(false)
  const classes = useStyles();

  const uploadDietFile=(e)=>{
    props.updateFeedback({loading:true})
    handleuploadImage(e).then((result)=>{
      props.updateFeedback({loading:false})
props.updateProgram({DietPlan:{...props.ProgramDetails.DietPlan,file:result.data.Location}})
    },err=> props.updateFeedback({loading:false}))
  }

  const saveProgram=()=>{
      props.saveProgram().then((result)=>{
          props.history.push(`${props.match.url}`)
      })
  }

  return (
    <Container>
      <Header button={
                     !editMode&& <Button 
                      onClick={()=>setEditMode(true)}
                      >
Edit
                        </Button>
                      
                      
                      }/>

      <Content>

{!editMode?<>
  <h2 className={classes.title} >Diet plan</h2>
     




<br/>



     <div className={classes.mainDiv}>
    <Grid container spacing={0}>
<Grid item xs={12}>
<b className={classes.labelBold}>
 Name
</b>
<p style={{color: "#172A44"}}>
{props.ProgramDetails.DietPlan.Title}
</p>
</Grid>

<Grid item xs={12} style={{marginTop:20}}>
<b className={classes.labelBold} >
Description
</b>
<p style={{ whiteSpace: "pre-wrap",color:"#172A44",lineHeight:1.7}}>
{props.ProgramDetails.DietPlan.Description}
</p>
</Grid>
</Grid>
     </div></>: 
     <>
     
     
     <input type="file" id={"dietFile"} onChange={uploadDietFile} style={{display:"none"}}/>
        <h2 className={classes.title}>Diet plan</h2>
    

<br/>


        <div className={classes.mainDiv}>
       <Grid container spacing={0}>
<Grid item xs={12}>
<CustomInput
                        labelText="TItle"
                        id="float"
                        bottomUnderline
                      style={{borderBottom:"none"}}
        inputProps={{
          style:!editMode?{marginTop:5,borderBottom:"none"}:{marginTop:5},
            value:props.ProgramDetails.DietPlan.Title,
            onChange:(e)=>props.updateProgram({ DietPlan:{...props.ProgramDetails.DietPlan,Title:e.target.value}}),
            placeholder:"Example, low carb, bulk",
            readOnly:!editMode
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
<Grid item xs={12}>
<CustomInput
                        labelText="Food"
                        id="float"
                        multiline
                        bottomUnderline
                        rows={6}
        inputProps={{
          value:props.ProgramDetails.DietPlan.Description,
          onChange:(e)=>props.updateProgram({ DietPlan:{...props.ProgramDetails.DietPlan,Description:e.target.value}}),
          placeholder:"Meal 1: fruits etc",
          style:!editMode?{marginTop:12,borderBottom:"none"}:{marginTop:12},
          readOnly:!editMode
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
 </Grid>
        </div>
     
     </>
     
     
     }





      </Content>
      {editMode&&<Footer actionButton>
        <Button
     onClick={saveProgram}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
        Save
        </Button>
      </Footer>}
    </Container>
  );
}
