import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import ResetMethod from "../Screens/passwordReset/resetMethod"
import Verify from "../Screens/passwordReset/verificationCode"
import NewPassword from "../Screens/passwordReset/newPassword"
import EmailPhone from "../Screens/passwordReset/typeEmailPhone"
import {connect} from "react-redux"
import {updateFeedback} from "../store/actions/feedback"
import {updateOnboarding} from "../store/actions/Onboarding"
import {initProfile} from "../store/actions/Profile"
 class Onboarding extends Component {

    

    state={
        type:null,
        password:"",
        uuid:"",
        token:null

    }
    componentDidMount=()=>{
       
    }
    setData=(data) => {
        this.setState(data)
    }
    render() {
        // if(this.props.Profile.token!==""&&this.props.Profile.token!==null){
        //     this.props.history.push("/instructor")
        // }
        return (
            <div>
                  <Route exact  path={`${this.props.match.path}/profile`} render={()=><ResetMethod {...this.props} data={this.state} setData={this.setData} type={"profile"} /> } />
                   <Route exact  path={`${this.props.match.path}/`} render={()=><ResetMethod {...this.props} data={this.state} setData={this.setData} type={""}/> } />
                   <Route exact  path={`${this.props.match.path}/verify`} render={()=><Verify {...this.props} data={this.state} setData={this.setData}/>} />
                   <Route exact  path={`${this.props.match.path}/new-password`} render={()=><NewPassword {...this.props} data={this.state} setData={this.setData}/>} />
                   <Route exact  path={`${this.props.match.path}/type-email-phone`} render={()=><EmailPhone {...this.props} data={this.state} setData={this.setData}/>} />
            </div>
        )
    }

}
const mapStateToProps =(state) => {
    return {
        
        Profile:state.Profile
    }
}

export default connect(mapStateToProps,{updateOnboarding,updateFeedback,initProfile})(Onboarding)