import React, { Component, useState, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import { makeStyles } from "@material-ui/core/styles";
import ArrowRight from "assets/svg/ArrowRight";
import "react-phone-input-2/lib/style.css";

import { connect } from "react-redux";
import {store} from "../../store"
import {createOrder} from "store/actions/common"
import {unsubscribe} from "store/actions/payments"
import { getSpecificPublicProgram } from "store/actions/createProgram";
const useStyles = makeStyles((theme) => ({
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    fontSize: 18,
    marginBlockStart: 0,
    marginBottom: 10,
    paddingTop: 10,
    color:"#172A44"
  },
  mainDiv: {
    padding: 25,
    paddingTop: 15,

    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
    background: "#FAFAFA",
    border: "1px solid #F3F3F3",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontFamily: "Proxima Nova",
    paddingLeft: 3,
    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },

  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },

  AvatarContainer: {
    display: "flex",
    justifyContent: "space-between",
    flexDirection: "row",
    width: "100%",
    paddingTop: 0,
  },
  iconContainer: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    flexDirection: "column",
    fontSize: "12px",
    color: "#172A44",
    fontFamily: "Proxima Nova",
  },

  priceMain: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: "24px",
    color: "#F73B3B",
    marginRight: 10,
  },
  priceStrike: {
    fontSize: "16px",
    lineHeight: "29px",

    color: "#747F8F",
  },

  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    fontWeight: "bold",
    color: "#172A44",
  },

  icons: {
    display: "flex",
  },
  banner: {
    width: "100%",
height:"56vw",

    borderRadius: "12px 12px 12px 12px",
    position: "relative",
    overflow: "hidden",
  },
  description:{
    fontSize:16,
    lineHeight:"29px",
    color:"#172A44",
    fontFamily: "Proxima Nova",
  },
  bannerName: {
    position: "absolute",
    top: 0,
    height: "100%",

    width: "100%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },
  content: {
    lineHeight: "24px",
    color: "#172A44",
    whiteSpace: "pre-wrap"
  },
  Avatar: {
    display: "flex",
    flexDirection: "row",
    alignItems: "center",
    marginTop: 15,
  },
  detail:{
    fontSize:16,
    color: "rgba(23, 42, 68, 0.75)",
    marginBottom:15,
    lineHeight:"15px"

  },
  dark:{
    color: "#172A44"
  }
}));

function Screen2(props) {
  const classes = useStyles();
  const [data, setData] = useState({
    BannerImage: null,
  });

  useEffect(() => {
    if(props.id)
{ 
  props.updateFeedback({loading:true})
  props.getOrder(props.id).then((Orderdata) => {
   let dataPr=Orderdata.Program
    props.updateFeedback({loading:false})
    console.log(Orderdata)
      setData({ ...dataPr.Program, name:dataPr.Program.createdBy.name ,profilePic: dataPr.Program.createdBy.profilePic,SubscriptionId:Orderdata.Program.SubscriptionId});
    },(err)=>{



    });
}

  }, [props.id]);

  
const unsubscribeProgram=(data)=>{
  unsubscribe(data).then(res=>{
    props.history.replace("/athlete/my-programs")
  })
}
 
  return (
    <Container>
        <Header />
      <Content>
        <div style={{padding:"25px 25px 0px 25px"}}>
        <div
          className={classes.banner}
          style={{
            backgroundImage: data.BannerImage
              ? `url(${data.BannerImage})`
              : `url(${require("assets/img/fitness.jpg")})`,
            backgroundSize: "cover",
          }}
        >
         
         
     
        </div>
</div>
        <div className={classes.mainDiv}>
          <div className={classes.title}>{data.Title}</div>
          <div className={classes.description}>{data.Description}</div>

          <div className={classes.title} style={{marginTop:10,marginBottom:15}}>Program details</div>

          <div className={classes.detail}>Duration: <span className={classes.dark}>4 weeks</span></div>
          <div className={classes.detail}>Type: <span className={classes.dark}>{data.PaymentType}</span></div>
        <div className={classes.detail}>Price: <span className={classes.dark}>${data.Price}</span></div>
         
        </div>
      </Content>
      <Footer actionButton>
       { data.SubscriptionId?
        <Button
    
          variant="contained"
          fullWidth
          size="lg"
          bold
          onClick={()=>unsubscribeProgram(data.SubscriptionId)}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
         Unsubscribe
        </Button>:null }
      </Footer>
    </Container>
  );
}

export default connect(null, { getSpecificPublicProgram })(Screen2);
