import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"
import Button from "components/CustomButtons/Button.js"
import Dumbell from "assets/svg/Dumbell"
import MoreHorizIcon from '@material-ui/icons/MoreHoriz';
import LinearProgress from "@material-ui/core/LinearProgress"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {

    width: "97%",
position: "relative",
borderRadius:"26px 26px 0px 0px",
fontFamily:"Proxima Nova",
background:"#fff",
paddingTop:"60%",
boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)"

  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
  }
,
  content:{
      
     
    margin:30,
    
width:"100%",
  flexDirection:"column",
  justifyContent:"space-between",
  display: "flex",

     
  },

  progress:{
      transform:"rotate(-90deg)",
      width:"120%",
      height:"6px"
  },

progressDiv:{
    width:"20%",
    height:"100%",
    justifyContent: "center",
    alignItems:"center",
    display: "flex",
    flexDirection: "column"
}
,
  childDiv:{
 position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display:"flex",
  
    flexDirection:"row",

    borderRadius:"26px 26px 0px 0px",
    background: "rgba(23, 42, 68, 0.35)",
  
    
    
  },

 icon:{
position:  "absolute",
right:8,

top:8,

 },
  title:{ 
    
    color: "#fff",
 
      
    fontWeight:"bold",
      fontSize: "24px",
lineHeight: "29px",
letterSpacing: "0.0120588em"

    },

    subTitle:{
     
        fontSize: "16px",
  lineHeight: "29px",
  

  color: "#fff",
    
    },

  image:{
  
   width:"93%",

    paddingTop: "56.3%",
     background:"grey",
     borderRadius:"16px",
     marginBottom:10
    
  },
  label:{
      position:"absolute",
      bottom:20,
      color:"#fff",
      fontWeight:"bold"
  },

bottom:{
    
width:"100%",
position:"absolute",
background: "linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, #000000 100%)",
opacity: 0.85,
backdropFilter: "blur(4px)",
bottom: "0",

display: "flex",
flexDirection: "column",
justifyContent: "center",
alignItems:"center",

borderRadius: "0px 0px 22px 22px"
}
,
sub:{
    
    fontWeight:"bold",
      fontSize: "14px",
lineHeight: "29px",
paddingBottom: 10,

color: "#fff",
},
normal:{
    fontWeight:"normal"
},

progressSec:{
borderRadius:"26px 26px 26px 26px"
},
bottomButton:{
  display:"flex",
  flexDirection:"row",
  justifyContent:"space-between",
  alignItems:"center"
}



}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
title1, title2,
sub1, sub2,button,
progress,
backDrop

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.progressSec]:progress

})

const childDiv=classNames({
    [classes.childDiv]: true,
    [classes.progressSec]:progress
})

  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
        [classes.normal]:true
 
    })
  console.log(backDrop)
  return (
  
     <div className={mainDiv} style={{background:backDrop?`url(${backDrop})`:`url(https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg)`,backgroundSize: "cover"}}>
         <div className={childDiv}>
<div className={classes.content}>
<div>
    {title1&&<div className={classes.title}>{title1}</div>}

  <div className={classes.title}>{title2}</div>
<div className={classes.subTitle}>{sub1}</div>
</div>
{/* <div className={subtitle}>{sub2}</div> */}
{button&&
<div className={classes.bottomButton}>
<Button style={{width:"120px",background: "rgba(0, 126, 160, 0.75)"}} size="sm"  variant="contained">{button}</Button>
<div style={{display:"flex",flexDirection:"row",alignItems:"center"}}>
<Dumbell style={{color:"white",fontSize:35,marginRight:10}}/>
<span style={{color:"white",fontSize:22}}>

{sub2}
</span>

</div>
</div>
}
</div>

 {/* {progress&&<div className={classes.progressDiv} >
     <LinearProgress className={classes.progress} value={progress} variant="determinate"/>
     <small className={classes.label}>{progress}% Done</small>
 </div>} */}
         </div>

     </div>


 
  );
});


export default AnnouncCard;
