export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);

  useEffect(() => {
    props.getClientPrograms();
   }, []);

   console.log(props.AtheletePlan)
  return (
    <>
      <Header />
      {props.AtheletePlan.AllPrograms && props.AtheletePlan.AllPrograms.length == 0 ? (
        <Content flex>
          <h2 className={classes.title}>My Programs</h2>
          <div className={classes.secondary}>
            Here you will find all of your workout programs. Both public and
            private
          </div>

          <div className={classes.mainDiv2}>
            <div>
              <NoWorkout style={{ fontSize: "70vw" }} />
            </div>
          
          </div>
        </Content>
      ) : (
        <Content flex>
          <div>
            <h2 className={classes.title}>My Programs</h2>
            <div className={classes.secondary}>Select one active program</div>
          </div>
          <div className={classes.mainDiv}>
            {props.AtheletePlan.AllPrograms.map((item) => {
              return (
                <div
                  // onClick={() =>
                  //   props.history.push("/common/programDetails/" + item._id)
                  // }
                >
                  <ProgramCard
                    {...item}
                    name={item.createdBy.name}
                    onClick={()=>props.history.push("/athlete/programDetails/"+item._id)}
                    profilePic={item.createdBy.profilePic}
                    switch
                    checked={props.AtheletePlan.currentPlan == item._id}
                    setActive={checked=>props.switchExercise({...item, isActive:checked})}
                  />
                </div>
              );
            })}
          </div>
        </Content>
      )}
    </>
  );
}
