
import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";

// @material-ui/icons
import Face from "@material-ui/icons/Face";
import Chat from "@material-ui/icons/Chat";
import Build from "@material-ui/icons/Build";
import DietIcon from "assets/svg/DietIcon"
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import BottomNav from "components/BottomNav";
import NumberSelector from "components/CustomTabs/NumberTabs";
import styles from "assets/jss/material-kit-react/views/componentsSections/tabsStyle.js";
import InfoBox from "components/InfoBox";
import InsAthlete from "components/Card/InsAthlete";
import AnnouncCard from "components/Card/announcement";
import ChatCard from "components/Card/Chat"
import { Info } from "@material-ui/icons";
import UploadCard from "components/Card/UploadCard"
import Camera from "assets/svg/Camera"
import IconButton from '@material-ui/core/IconButton';
import AddIcon from "assets/svg/AddIcon"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar'
import Divider from '@material-ui/core/Divider';
import InboxIcon from '@material-ui/icons/Inbox';
import DraftsIcon from '@material-ui/icons/Drafts';
import WeightLifting from "assets/svg/WeightLifting"
import {theme} from "assets/css/theme"
import ArrowRight from "assets/svg/ArrowRight"
import ListItemSecondaryAction from '@material-ui/core/ListItemSecondaryAction';
import Avatar from '@material-ui/core/Avatar'
import Image from "assets/img/fitness.jpg"
import Chip from "@material-ui/core/Chip"
import Checkbox from "components/CheckBox";
import Star from "@material-ui/icons/StarRate"
import DraftIcon from "assets/svg/NewIcons/figgsWhite"
import Switch from "components/customSwitch";
const useStyles = makeStyles({
    mainDiv:{
        display:"flex",
        alignItems: "center",
        flexDirection: "row",
       padding:20,
       paddingTop:30,
       paddingBottom:0,
       paddingLeft:theme.padding,
       paddingRight:theme.padding,
 
        backgroundColor:"#fff",

    },
    Img:{
     alignItems: "center",
flex:2,

    },
    Item:{
        display:"flex",
        width:"100%",
        flexDirection:"row",
        justifyContent:"space-between",
flex:3
    },
    main:{
        display:"flex",
        flexDirection:"column",
        justifyContent:"center",
        width: "100%",
    },
    header:{
        display:"flex",
        flexDirection:"row",
 
        paddingLeft:15,
        alignItems: "center"
      
    },
    text:{
        fontFamily:"Proxima Nova",
        marginLeft:5,
        display:"flex",
        alignItems: "center",
        fontSize:12,
        color:"#172A44",
        textTransform:"capitalize"
    },
    content:{
        fontSize:18,
        
        padding:"0px 15px 0px 15px",
       
        textTransform:"capitalize",
       
        fontFamily:"Proxima Nova",
        color:"#172A44"
    },
    chip:{
        position:"absolute",
        top:10,
        left:10,
      
        
    },
    overlay:{
        width:"100%",
        height:"100%",
        backgroundColor: "rgba(0, 126, 160, 0.75)",
        display:"flex",
        flexDirection:"row",
        justifyContent:"center",
        position:"absolute",
        overflow:"hidden",
        borderRadius:12,
        alignItems:"center"
    }
});

export default function SectionTabs(props) {
  const classes = useStyles();



  return (
    <>
  <div className={classes.mainDiv} onClick={props.onClick?props.onClick:null}>
      <div className={classes.Img}>
      <div style={{backgroundImage:props.BannerImage&&!props.IsDraft?`url(${props.BannerImage})`:!props.IsDraft?`url(${Image})`:null,width:"100%",paddingBottom:"66%",backgroundSize: "cover",borderRadius:16,position:"relative"}}>
   {props.IsDraft&& <div className={classes.overlay}>
<DraftIcon style={{fontSize:40}}/>
    </div>}
      </div>
</div>
                     
                         
                         <div className={classes.Item}>
                             <div className={classes.main}>
                                 {!props.noAvatar&&<div style={{display:"flex",flexDirection:"row",justifyContent:"space-between"}}>
                                 <div className={classes.header}>
<Avatar size={"small"} style={{height:25,width:25}} src={props.profilePic}/>
<div className={classes.text}>{props.name}</div>
</div>


{props.switch&&<Switch
                      checked={props.checked}
                       onChange={event => props.setActive(event)}
               
                     
                    />}

               



                                 </div>}

<div className={classes.content}>
{props.Title}
</div>

                             </div>


                            {!props.switch&&!props.Checkbox&& <div style={{alignItems:"center",display:"flex",paddingRight:10}}>
                     <IconButton edge="end" aria-label="delete" style={{borderRadius:"11px"}}>
                     <ArrowRight color="primary" style={{fontSize:18}} />
                   </IconButton></div>}

                   {props.Checkbox&&< Checkbox    onClick={event => {event.stopPropagation();props.setActive(props._id)}}
                      checked={props.checked} />}


                     </div>

  </div>
     
      <div style={{display:"flex",flexDirection:"row",flex:1,marginLeft:25,marginRight:25}}>
<div style={{display:"flex",flexDirection:"row",flex:2.2}}></div>
<div style={{display:"flex",flexDirection:"row",flex:3,borderBottom:"1px solid #E2E2E2"}}><Divider/></div>

      </div>
     
  </>
  );
}
