import React, { useState, useEffect } from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import axios from "utils/axios";
import api from "utils/api";
import DietIcon from "assets/svg/DietIcon";
// @material-ui/core components
import ReactPlayer from "react-player";
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar";
import Divider from "@material-ui/core/Divider";
import Progress from "components/Progress/CircularProgree";
import moment from "moment";
import Image from "assets/img/fitness.jpg"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",
    display: "flex",
    flexDirection: "row",
    marginTop: 20,
    fontFamily: "Lato",
    justifyContent: "flex-start",

    borderRadius: 10,
  },

  mainReverse: {
    justifyContent: "flex-end",
  },

  content: {
    width: "auto",
    maxWidth: "75%",
    minWidth: 120,
   
    fontSize: 14,
    background: "#ECEEEF",
    position: "relative",
    padding: 15,
    paddingBottom:25,
    color: "#172A44",
    lineHeight:"22px",
    borderRadius: "10px 10px 10px 10px",
  },

  white: {
    background: "#D6F5FE",

  
    boxSizing: "border-box",
    borderRadius: "10px 10px 10px 10px",
 
    maxWidth: "75%",
  },
  childDiv: {
    position: "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
  },

  icon: {
    fontSize: 60,
  },
  title: {
    color: "#172A44",

    fontSize: 16,
    display: "inline",
  },

  images: {
    display: "flex",
    width: "100%",
    flexDirection: "row",
  },
  image: {
    width: "50%",

    marginTop: 10,
    borderRadius: "12px",
  },
  inside: {
    width: "90%",

    paddingTop: "80%",
    borderRadius: "12px",
    background: "black",
  },
  time: {
    display: "flex",
    flexDirection: "row",
    justifyContent: "flex-end",
    paddingRight: 10,
    color: "#747F8F",
    fontSize: 12,
    width: "200%",
    position: "absolute",
    right: 0,
    bottom: 0,
    fontFamily: "Proxima Nova",
  },
  subTitle: {
    fontFamily: "Proxima Nova",

    fontSize: 14,

    lineHeight: "22px",
  },

  imageStyle: {
    borderRadius: 5,
    width: "100%",
  },
  Progress: {
    position: "absolute",

    bottom: 0,
    right: 0,
    background: "#fffff",
    borderRadius: "50%",
    zIndex: 2000,
  },
  bannerImage:{
    width:"100%",
    borderRadius:6
  },

  planTitle:{
    fontFamily: "Proxima Nova",
    paddingLeft:15,
    paddingRight:15,
    fontWeight: "bold",
    fontSize: "14px",
    lineheight: "22px",
    /* or 183% */
    
 
    color: "#172A44"
  },
  PurchaseButton:{
    fontFamily: "Proxima Nova",
fontStyle: "normal",
textDecoration: "underline",
fontWeight: "normal",
fontSize: "16px",
lineHeight: "28px",
/* or 186% */


textAlign: "center",
marginTop:10,
color: "#007EA0"
  },

  reverseText:{
    
  },
  noPadding:{
    paddingTop:0,
    paddingLeft:0,
    paddingRight:0
  }
}));

const AnnouncCard = React.forwardRef((props, ref) => {
  const [val, setVal] = useState(
    props.data.UploadPercentage ? props.data.UploadPercentage : 0
  );
  const [upload, setUpload] = useState(
    props.data.IsUploading && props.data.IsUploading == true ? true : false
  );
  const [file, setFile] = useState(props.UploadFile);

  const { selected, Title, Text, Icon, Time, white, reverse, Images } = props;

  const classes = makeComponentStyles();

  const content = classNames({
    [classes.content]: true,
[classes.noPadding]:props.data.SentProgramId,
    [classes.white]: reverse,
  });

  const mainDiv = classNames({
    [classes.mainDiv]: true,
    [classes.mainReverse]: reverse,
  });

  const icon = classNames({
    [classes.icon]: true,
    [classes.selected]: selected,
  });

  const time = classNames({
    [classes.time]: true,
    [classes.reverseText]: reverse,
  });

 

  
  useEffect(() => {
    if (
      props.data.IsUploading !== undefined &&
      props.data.IsUploading !== true &&
      props.UploadFile
    ) {
      props.updateChat({ ...props.data, IsUploading: true }, props.to);

      setUpload(true);
      const form = new FormData();
      if (props.data.uploadType == "audio") {
        form.append("rsfile", props.UploadFile, "muAudio.mp3");
      } else form.append("rsfile", props.UploadFile);

      axios
        .post(`${api.protocol}${api.baseUrl}${api.UploadSingleFile}`, form, {
          onUploadProgress: (progressEvent) => {
            let uploadPercentage = parseInt(
              Math.round((progressEvent.loaded / progressEvent.total) * 100)
            );
            setVal(uploadPercentage);
            props.updateChat(
              { ...props.data, UploadPercentage: uploadPercentage },
              props.to
            );
          },
        })
        .then((result) => {
          setUpload(false);
          // setFile(result.data.Location)

          if (props.data.uploadType == "image") {
            props.AddChatData(
              { ...props.data, Images: [result.data.Location] },
              props.to
            );
            props.updateChat(
              { ...props.data, Images: [result.data.Location] },
              props.to
            );
          } else if (props.data.uploadType == "video") {
            props.AddChatData(
              { ...props.data, Video: result.data.Location },
              props.to
            );
            props.updateChat(
              { ...props.data, Video: result.data.Location },
              props.to
            );
          } else if (props.data.uploadType == "audio") {
            props.AddChatData(
              { ...props.data, Audio: result.data.Location },
              props.to
            );
            props.updateChat(
              { ...props.data, Audio: result.data.Location },
              props.to
            );
          }

          //  props.handleSuccess(result.data.Location)
        })
        .catch((error) => {
          // props.handleError(error)
        });
    }
  }, [props.UploadFile]);

  return (
    <div>
      <div className={mainDiv}>
        {/* {!reverse && (
          <div className={classes.avatar}>
            <Avatar>H</Avatar>
          </div>
        )} */}
        <div className={content}>
          <div
            style={{ postion: "relative", width: "100%" }}
           
          >
            {props.Images && props.Images.length > 0 ? (
              <img className={classes.imageStyle} src={props.Images[0]} 
              onClick={() =>
                props.onClickImage(
                  props.Images && props.Images.length > 0
                    ? props.Images[0]
                    : URL.createObjectURL(file)
                )
              }
              />
            ) : (
              props.data.UploadFile &&
              props.data.uploadType == "image" && (
                <img
                  onClick={() => props.onClickImage(file)}
                  className={classes.imageStyle}
                  src={URL.createObjectURL(file)}
                />
              )
            )}




            {props.data.Video ? (
              <ReactPlayer
                playing={false}
                controls={true}
                style={{
                  width: "100%",
                  height: "auto",
                  borderRadius: 10,
                  overflow: "hidden",
                }}
                width="100%"
                height="100%"
                url={props.data.Video}
              />
            ) : (
              props.data.UploadFile &&
              props.data.uploadType == "video" && (
                <ReactPlayer
                  playing={false}
                  controls={true}
                  style={{
                    width: "100%",
                    height: "auto",
                    borderRadius: 10,
                    overflow: "hidden",
                  }}
                  width="100%"
                  height="100%"
                  url={URL.createObjectURL(file)}
                />
              )
            )}





            {props.data.Audio ? (
              <audio controls style={{ width: "60vw" }}>
                <source src={props.data.Audio} />
              </audio>
            ) : (
              props.data.UploadFile &&
              props.data.uploadType == "audio" && (
                <audio controls style={{ width: "80vw" }}>
                  <source src={URL.createObjectURL(file)} />
                </audio>
              )
            )}




            {
props.data.SentProgramId&&
<>
<img src={props.data.SentProgramId.Program.BannerImage?props.data.SentProgramId.Program.BannerImage:Image} className={classes.bannerImage} />

<center>
            <span className={classes.planTitle} style={{color:"#172A44"}}>{props.data.SentProgramId.Title}</span><br/>
         
</center>
<Divider style={{marginTop:5,color: reverse?"#fff":"#fff"}}/>


{<div className={classes.PurchaseButton} style={{color:"#172A44"}}>

View
</div>}






</>


            }

            {upload && (
              <div className={classes.Progress}>
                <Progress value={val}  />
              </div>
            )}
          </div>
          <div className={classes.subTitle}>{Text}</div>
          <span className={time} >{props.data.createdAt?moment(props.data.createdAt).startOf().fromNow():moment(props.data.createdAt).startOf().fromNow()}</span>
        </div>
      </div>
    </div>
  );
});

export default AnnouncCard;
