export default function Screen2(props) {
  const classes = useStyles();
  const [open,toggle]=useState(false)
  const [expertise,setExpertise]=useState(props.Profile.expertise)

const handleEdit=(e)=>{

  props.updateProfile({expertise:expertise}).then((res)=>{
    props.history.goBack()
  })
toggle(false)
}
 

console.log(props)
  return (
    <Container>
<Header />

      <Content flex>
      <span className={classes.title}>Fitness expertise</span>
        <p className={classes.secondary}>Tag your expertise.</p>
        <div className={classes.mainDiv}>
                 
        <Grid item xs={12}>
        <br/>
   <CustomInput
                      
                     
                      bottomUnderline
                      labelText="Experiance"
                      id="float"

        inputProps={{
            value:expertise,
            style:{marginTop:10},
            onChange:(e)=>setExpertise(e.target.value),
           placeholder:"Bodybuilding, yoga, CrossFit"
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />

</Grid>
        </div>

     
      </Content>
      <Footer actionButton>
        <Button
         onClick={handleEdit}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
