import axios from "utils/axios"
import api from "utils/api"




export const getClientPrograms = ()=>{
  return (dispatch,getState)=>{
  return new Promise((res,reject)=>{
 
    axios.get(`${api.protocol}${api.baseUrl}${api.allOrder}`).then((response)=>{
      console.log(response.data)
        let allPrograms=response.data.Programs.map(item=>{return(
            {...item.Program,...item}
        )})

        let activeProg=allPrograms.find(act=>act.isActive==true)

        if(activeProg&&activeProg._id!==getState().AtheletePlan.currentPlan){
          

          dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
          axios.patch(`${api.protocol}${api.baseUrl}${api.switchProgram}`,{_id:activeProg._id,isActive:activeProg.isActive}).then((response)=>{
             
            dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
            
          
      console.log(response)
      let data=response.data.data
         
      if(activeProg.isActive)
             { 
               dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{
              Instructor:{...data.Program.createdBy},
              DietPlan:{...data.Program.DietPlan},
                  Exercises:{...data.Program},
                  currentPlan:data._id,
                  currentWeek: data.currentWeek,
                  currentDay:data.currentDay
           
              }})
            
            }
            
             else{
      
              dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{
                
                DietPlan:{},
                Instructor:{},
                currentPlan:null,
                Exercises:{_id:null}
              
              }})
             }
      
      
              return res("success")
            }).catch((err)=>{
                console.log(err)
                dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
                  return reject("error")
                  
                 })
      
      
              

        }

        // let activeProgram=response.data.Programs.findIndex(item=>{return item.isActive})

console.log(allPrograms)
     

        dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{AllPrograms:allPrograms}})
       


        return res("success")
      }).catch((err)=>{
        if(err.response&&err.response.status==404){
          
        dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{AllPrograms:[],DietPlan:{},Exercises:{}}})
        }
          console.log(err)
            return reject("error")
           })


        })
      }
}

export const getOrder = (id)=>{
  return (dispatch,getState)=>{
  return new Promise((res,reject)=>{
 
    axios.get(`${api.protocol}${api.baseUrl}${api.getOrder}${id}`).then((response)=>{
      
   
      
console.log(response.data)

        dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{
            Instructor:{...response.data.Program.Program.createdBy},
            DietPlan:{...response.data.Program.Program.DietPlan},
            Exercises:{...response.data.Program.Program,orderId:response.data._id},
          
        }})
      
       

     


        return res(response.data)
      }).catch((err)=>{
        if(err.response.status==404)
        dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{DietPlan:{},Exercises:{}}})
          console.log(err)
            return reject("error")
           })


        })
      }
}

export const switchExercise=(exercise)=>{
  console.log(exercise)
  return (dispatch,getState)=>{

    return new Promise((res,reject)=>{
      dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
      axios.patch(`${api.protocol}${api.baseUrl}${api.switchProgram}`,{_id:exercise._id,isActive:exercise.isActive}).then((response)=>{
         
        dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
        
      
  console.log(response)
  let data=response.data.data
     
  if(exercise.isActive)
         { 
           dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{
          Instructor:{...data.Program.createdBy},
          DietPlan:{...data.Program.DietPlan},
              Exercises:{...data.Program},
              currentPlan:data._id,
              currentWeek: data.currentWeek,
              currentDay:data.currentDay
       
          }})
        
        }
        
         else{
  
          dispatch({type:"UPDATE_ATHLETE_PLAN",payload:{
            
            DietPlan:{},
            Instructor:{},
            currentPlan:null,
            Exercises:{_id:null}
          
          }})
         }
  
  
          return res("success")
        }).catch((err)=>{
            console.log(err)
            dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
              return reject("error")
              
             })
  
  
          })
        }
}



