export const getClients=()=>{
return (dispatch, getState)=>{
  return new Promise((res,reject)=>{
   
    axios.get(`${api.protocol}${api.baseUrl}${api.getClients}`).then((response)=>{
      
      dispatch({ type:"UPDATE_INSTRUCTOR_CLIENTS" ,payload:{clients:response.data.clients}})
    

        return res(response.data.clients)
      }).catch((err)=>{
          console.log(err)
          if(err.response.status==404)
         { 
          dispatch({ type:"UPDATE_INSTRUCTOR_CLIENTS" ,payload:{clients:[]}})
          return reject(err.response.status)
        
        
        }
          else
            return reject("error")
           })


        })
}
  
        
}

