import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon";
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar";
import MoreHorizIcon from "@material-ui/icons/MoreHoriz";
import IconButton from "@material-ui/core/IconButton";
import AddIcon from "@material-ui/icons/Add";

const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    width: "100%",
height:"100%",
    borderRadius: "16px",
    fontFamily: "Proxima Nova",
    background: "#fff",
    border: "3px solid #E4F0F4",
  },

  white: {
    background: "#fff",
    boxShadow:
      "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
    boxSizing: "border-box",
  },
  content: {
    width: "80%",
   
    display: "flex",
    flexDirection: "row",
    justifyContent: "space-between",
    marginTop: "15px",

    position:"relative"
  },

  childDiv: {
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    flexDirection: "column",

    borderRadius: "16px",
  },

  icon: {
    fontSize: 60,
  },
  title: {
    display: "flex",
    color: "#172A44",
    alignItems: "flex-start",
    flexDirection: "column",
    fontSize: "14px",
    fontWeight: "500",
    lineHeight: "20px",
  },

  subTitle: {
    color: "#172A44",
    fontWeight: 500,

    fontSize: "16px",
    lineHeight: "20px",
  },

  image: {
    width: "93%",
 
    position: "relative",
    paddingTop: "56.3%",
  
    borderRadius: "16px",
    marginBottom: 10,
  },
  insideIcon: {
    position: "absolute",
    top: 0,
    width: "100%",
    height: "100%",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    background: "#fff",
  },
  iconMore:{
position:"absolute",
top:0,
right:0
  }
,
  data: {
    /* or 161% */

    color: "#F73B3B",
    fontWeight: "bold",
    fontSize: "18px",
    lineHeight: "28px",
  },
  sub: {
    fontWeight: "bold",
    fontSize: "14px",
    lineHeight: "28px",
    textDecorationLine: "line-through",
    marginLeft: 10,
    color: "#CECECE",
  },
}));

const AnnouncCard = React.forwardRef((props, ref) => {
  const { selected, Title, Text, Icon, Time, white, Image } = props;
  const classes = makeComponentStyles();
  const mainDiv = classNames({
    [classes.mainDiv]: true,
  });

  const icon = classNames({
    [classes.icon]: true,
    [classes.selected]: selected,
  });

  const title = classNames({
    [classes.title]: true,
    [classes.selected]: selected,
  });

  const subtitle = classNames({
    [classes.subTitle]: true,
  });

  return (
    
    <div className={mainDiv}>
      <div className={classes.childDiv}>
        <div className={classes.content}>
          <div className={title}>
            {Title}
            <br />

            <div style={{ fontSize: 16, color: "#747F8F" }}> {Text?Text:"Untitled"}</div>
          </div>

           {/* <div className={classes.iconMore}   onClick={props.onClickMore}>
          
          
           
              <MoreHorizIcon />
          
          </div>  */}
        </div>
        <div
          className={classes.image}
          onClick={props.onClickImage}
          style={ Image&&{
             backgroundImage: `url(${Image})`,
            backgroundSize: "cover",
          }}
        >
         
        </div>
      </div>
    </div>
  );
});

export default AnnouncCard;
