export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);

  useEffect(() => {
     props.getClientPrograms();
    
  }, []);

  console.log(props.AtheletePlan.Exercises)
  let carouselItems=[]
  props.AtheletePlan.Exercises._id&&props.AtheletePlan.Exercises.ExercisePlan[props.AtheletePlan.currentWeek].map((item,index)=>{
 
  if(item.Exercise.length>0)
  carouselItems.push(<WorkoutCard
  title2={`Day ${index+1}: ${item.Title}`}
  sub1={props.AtheletePlan.Exercises.Title}
  sub2={item.Exercise.length}
  button={"Start Now!"}
  progress={40}
  backDrop={item.Cover}
  style={{marginLeft:10,marginRight:10}}
  />
  )

  })
  
  return (
    <>
   
      {props.AtheletePlan.AllPrograms&&props.AtheletePlan.AllPrograms.length == 0 ? (
        <Content flex>
          <h2 className={classes.title}>Daily Workout</h2>
          <div className={classes.secondary}>
           Your daily workout, diet plan and instructor.
          </div>
          <div className={classes.searchBar}>
          <CustomInput
              id="material"
              inputProps={{
                onChange:(e)=>props.history.push(`/athlete/view/1?search=${e.target.value}`),
                style: { background: "#fafafa",marginBottom:0 },
                placeholder: "Search for instructor ",
                startAdornment: (
                  <InputAdornment position="start">
                <SearchIcon style={{color: "rgba(23,42,68,0.3)"}} />
                  </InputAdornment>
                ),
                endAdornment: (
                 <>{value? <InputAdornment position="end" onClick={e=>console.log("")}>
                  <CancelIcon />
                </InputAdornment>:null}</>
                 )
              }}
              formControlProps={{
                fullWidth: true,
              }}
            />
            </div>


          <div className={classes.mainDiv2}>
            <div>
            <img src={require('assets/img/gym.png')}  style={{width:"70vw",height:"auto"}}/>
            </div>
            <div className={classes.secondary} style={{textAlign:"center",maxWidth:"70vw"}}>
            Purchase a program to active your daily workout page
          </div>
          </div>
        </Content>
      ) : (
        <Content flex>
          <h2 className={classes.title}>Daily Workout</h2>
         <br/>
          <Carousel items={carouselItems} currentDay={props.AtheletePlan.currentDay?props.AtheletePlan.currentDay:0}/>
        
          <div className={classes.mainDiv}>
          <List style={{width: "100%"}}>
<ListItem 
bordered
icon={<DietIcon style={{fontSize:53}}/>}
Title={"View diet plan"}
Secondary={props.AtheletePlan.DietPlan.Title}
onClick={()=>props.history.push(props.AtheletePlan.Exercises._id?`${props.match.path}/dietplan`:`${props.match.path}/my-programs`)}
/>

<ListItem 
bordered
icon={<CalenderIcon  style={{fontSize:53}}/>}
Title={"Workouot Calender"}
Secondary={"23 days left"}
onClick={()=>props.history.push(props.AtheletePlan.Exercises._id?`${props.match.url}/exercise-calender`:`${props.match.path}/my-programs`)}

/>

<ListItem 
bordered
icon={<Instructor style={{fontSize:53}}/>}
Title={"My instructor"}
Secondary={props.AtheletePlan.Instructor.name}
url={props.AtheletePlan.Instructor.profilePic}
onClick={()=>props.history.push(props.AtheletePlan.Instructor._id?`/common/instructorProfile/${props.AtheletePlan.Instructor._id}`:`${props.match.path}/my-programs`)}
/>

<ListItem 
icon={<ActiveProgramIcon style={{fontSize:53}}/> }
Title={"Active Program"}
Secondary={props.AtheletePlan.Exercises.Title}
onClick={()=>props.history.push(`${props.match.path}/my-programs`)}
/>
</List>
</div>



        </Content>
      )}
    </>
  );
}
