import {
  primaryColor,
  dangerColor,
  successColor,
  defaultFont
} from "assets/jss/material-kit-react.js";

const customInputStyle = {
  disabled: {
    "&:before": {
      borderColor: "transparent !important"
    }
  },


  underline: {
    borderRadius: "12px",
    border: "1px solid rgba(23,42,68,0.25)",
boxSizing: "border-box",

    "&:hover:not($disabled):before,&:before": {
      borderColor: "red",
      border:0,
      borderWidth: "1px"
    },
    "&:after": {
      border:0,
      borderColor: "red",

      
    }
  },

  BottomUL:{
    borderRadius:0,
    border:"none",
    borderBottom: "0.5px solid #D4D7DC",
boxSizing: "border-box",
  }
  ,
  
  whiteUnderline: {
    "&:hover:not($disabled):before,&:before": {
      borderColor: "#FFFFFF"
    },
    "&:after": {
      borderColor: "#FFFFFF"
    }
  },
  labelRoot: {
    
    fontFamily: "Proxima Nova",

    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    /* or 181% */
    
    
    color: "#172A44"
  
   
  },
labelUnderline:{
  lineHeight: "24px",
},
  mobile:{
    padding:"10px 10px 10px 2px",
    borderRadius: "12px",
    border: "0.5px solid #D4D7DC",
boxSizing: "border-box",

  },

  mobileInput:{
   border:"0px solid white",
    height: "unset",
    color: "#172A44",
    
    "&,&::placeholder": {
     
      fontFamily: "Proxima Nova",
 fontWeight:"normal",

  fontSize:"14px",
   paddingLeft:"5px",
  

    },
  },
  mobileButton:{
    backgroundColor:"#fff",
    borderRadius: "12px",
  },

  root:{
    display: "flex",
    flexDirection:"row",
    justifyContent:"center",
    alignItems:"center",
    padding:"10px 18px",
  
  },
  rootUnderlined:{
    padding:"10px 0px",
  },

  labelRootError: {
    color: dangerColor + " !important"
  },
  labelRootSuccess: {
    color: successColor + " !important"
  },
  whitebase:{
    background: "white",
   
    borderRadius: "11px",
    "&,&::placeholder": {

fontFamily:"Proxima Nova",
fontStyle: "normal",
fontWeight: "bold",
fontSize: "14px",
lineHeight: "17px",

/* identical to box height */


color: "#172A44"
    }
  },

  whitebaseUnderLine:{
    border: "1px solid #F3F3F3",
    boxSizing: "border-box",
  },
 
  formControl: {
    margin: "0 0 17px 0",
   
    position: "relative",
    
    "& svg,& .fab,& .far,& .fal,& .fas,& .material-icons": {
      color: "#495057",
     
  
    }
  },

  borderedWhite:{
    border: "3px solid #E4F0F4",
    boxSizing: "border-box",
    borderRadius: "11px",



      
    },

    rootBoxed:{
      background: "#FFFFFF",
      boxShadow: "inset 1px 1px 3px rgba(105, 141, 173, 0.4)",
      borderRadius: "12px"
    }
,
    boxed:{
     
      textAlign: "center",
    
      
        fontFamily: "Proxima Nova",
   
  
    fontSize:"22px",

   
     fontWeight: "bold",
  color: "#172A44"
    }
  ,
  
  lgCentered:{
    maxWidth: "200px",
    textAlign: "center",

    
      fontFamily: "Proxima Nova",
 

  fontSize:"32px",
 
  
color: "#172A44"
    
  }
  
  ,
  input: {
    color: "#172A44",
    height: "unset",
  
    "&::placeholder": {
    
      fontFamily: "Proxima Nova",
 fontWeight:"normal",

  fontSize:"14px",
   paddingLeft:"5px",
  
color: "#172A44"
    },
  
  },
  underlineInput:{
    color: "#007EA0",
    fontFamily: "Proxima Nova",
    "&::placeholder": {
    
      fontFamily: "Proxima Nova",
 fontWeight:"normal",

  fontSize:"14px",
   paddingLeft:"0px",
  
color: "#172A44"
    },
  }

  ,

  inputError:{
    borderBottom: "0.5px solid #DD3E3E",
  },

  helperError:{
    color: "#DD3E3E",
    fontSize:14,
    marginTop:10,
    marginLeft:3
  }
};

export default customInputStyle;
