import api from "utils/api"
import IconButton from "@material-ui/core/IconButton"
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemSecondaryAction from "@material-ui/core/ListItemSecondaryAction";
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
   textTransform:"capitalize",
marginBottom: "10px",
color: "#172A44",
    fontSize: "24px",
  },

  subTitle: {
    fontStyle: "normal",
    textTransform:"capitalize",
    fontWeight: "normal",
    fontSize: "16px",
    lineHeight: "20px",
    /* or 125% */
    color: "#747F8F",
  },

  mainDiv: {
    padding: 25,
    paddingTop: 35,

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 5,
    color: "#172A44",
    fontWeight: 500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
  },
  Image: {
    width: "50vw",
    height: "50vw",
  },
  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },
  Banner: {
    position: "relative",
    width: "100%",
    height: "50vw",
    backgroundColor: "rgba(23, 42, 68, 0.25)",

    borderRadius: "0px 0px 22px 22px",
  },
  bannerIcon: {
    position: "absolute",
    top: "20vw",
    left: "43vw",
    fontSize: 50,
  },
  Avatar: {
    position: "absolute",

    bottom: -25,
    width: 60,
    height: 60,
    left: 30,
    border: "5px solid white",
  },
  city: {
    fontSize:"16px",
   
       fontFamily: "Proxima Nova",
       color: "#007EA0",
       paddingTop: 10,
     },
     
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [val, setVal] = useState(null);


  const uploadProfilePic = (e) => {
    props.updateFeedback({ loading: true });
    handleuploadImage(e).then(
      (res) => {
        props.updateOnboarding({ profilePic: res.data.Location });
        props.updateFeedback({ loading: false });
      },
      (rej) => {
        if (rej == "size")
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Image size should be less than 5 mb",
            severity: "warning",
          });
        else
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Error in uploading image please try again later",
            severity: "warning",
          });
      }
    );
  };

  const uploadBanner = (e) => {
    props.updateFeedback({ loading: true });
    handleuploadImage(e).then(
      (res) => {
        props.updateOnboarding({ banner: res.data.Location });
        props.updateFeedback({ loading: false });
      },
      (rej) => {
        if (rej == "size")
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Image size should be less than 5 mb",
            severity: "warning",
          });
        else
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Error in uploading image please try again later",
            severity: "warning",
          });
      }
    );
  };

  const handleChange = (value, index) => {
    let arr = [...props.Profile.links];

    if (value) {
      arr[index] = value;
    } else {
      arr.splice(index, 1);
    }
    props.updateOnboarding({ links: arr });
  };

  const addNewLink = (e) => {
    let arr = [...props.Profile.links];
    if (e.target.value) {
      arr.push(e.target.value);
      props.updateOnboarding({ links: arr });
      setVal("");
    }
  };

  return (
    <Container>
      <Navbar
        navbarProps={{
          position: "fixed",
          style: { background: "none", boxShadow: "none" },
        }}
      />

      <Content>
        <div
          className={classes.Banner}
          style={{
            backgroundImage: `url(${props.Profile.banner})`,
            backgroundSize: "cover",
          }}
        >
          {!props.Profile.banner && (
            <Camera

              className={classes.bannerIcon}
              onClick={() => document.getElementById("banner").click()}
            />
          )}
          <input
            type="file"
            id="banner"
            onChange={uploadBanner}
            style={{ display: "none" }}
          />
          <input
            type="file"
            id="profile"
            onChange={uploadProfilePic}
            style={{ display: "none" }}
          />

          <Avatar
          style={{backgroundColor:props.Profile.profilePic?"#fafafa":"none"}}
            className={classes.Avatar}
            src={props.Profile.profilePic}
          ></Avatar>
        </div>
        <div className={classes.mainDiv}>
          <div className={classes.title}>{props.Profile.name}</div>

        
   
          <div className={classes.secondary}>{props.Profile.type=="Instructor"?props.Profile.bio:props.Profile.healthGoals}</div>
          <div style={{ marginTop: 10 }}>
           {props.Profile.location&& <span className={classes.city}>
              <Location style={{ fontSize: 14,marginRight:5 }} />
              {getLocation(props.Profile.location)}
            </span>}
          </div>
          <Button
            variant="outlined"
            fullWidth
            style={{ marginTop: 25, marginBottom: 17 }}
            size="sm"
            onClick={() => props.history.push("/profile/edit")}
          >
            Edit Profile
          </Button>

          {
          <Grid container>
          <Grid item xs={12}>
            <List >
                <ListItem button style={{paddingLeft:0,paddingRight:0,paddingTop:15,paddingBottom:15}} onClick={() =>props.history.push(`${props.match.url}/health-info1`)}>
                    <ListItemIcon>
                       
                        <Heart style={{color:"#F9FCFD",fontSize:44}}/>
                       
                   
                    </ListItemIcon>
                    <ListItemText primaryTypographyProps={{style:{fontSize:18}}} primary="Health information" />
                    <ListItemSecondaryAction>
                        <ArrowRight color="primary" style={{fontSize:18}}/>
                        </ListItemSecondaryAction>
                </ListItem>
                <Divider/>
              
                <ListItem button style={{paddingLeft:0,paddingRight:0,paddingTop:15,paddingBottom:15}} onClick={() =>props.history.push(`${props.match.url}/body-images`)}>
                    <ListItemIcon>
                       
                        <Camera style={{color:"#F9FCFD",fontSize:44}} color="primary"/>
                        
                   
                    </ListItemIcon>
                    <ListItemText primary="Body images" primaryTypographyProps={{style:{fontSize:18}}} />
                    <ListItemSecondaryAction>
                        <ArrowRight color="primary" style={{fontSize:18}}/>
                        </ListItemSecondaryAction>
                </ListItem>

            </List>
            </Grid>
            {/* <Grid item xs={12}>
            <div style={{marginTop: 10 }}>
   <UploadCard  files={props.Profile.bodyImages} sm Title={""} Icon={(cls)=><Camera color="primary" style={{fontSize:40}}/>}  handleUpdate={(files)=>props.updateInfo({bodyImages:files})} ViewMode/>
    </div>
            </Grid> */}
          </Grid>}
        </div>
      </Content>
    
    </Container>
  );
}
