import React, { Component, useState, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Typography from "@material-ui/core/Typography";
import { getLocation } from "utils/helpers";
import { makeStyles } from "@material-ui/core/styles";
import Grid from "@material-ui/core/Grid";
import ArrowForwardIosIcon from "@material-ui/icons/ArrowForwardIos";
import Avatar from "components/Avatar";
import ProfileBanner from "assets/img/screens/profileBanner.png";
import Camera from "assets/svg/Camera";
import Muted from "components/Typography/Muted";
import Location from "assets/svg/Location";
import Navbar from "components/Navbar";
import Workout2 from "components/Card/workoutTitleOnly";

import { fetchUser, fetchPrograms } from "store/actions/common";
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    textTransform: "capitalize",
    fontSize: 24,
    marginTop:5,
  },
  title2: {
    fontFamily: "Proxima Nova",
color: "#172A44",
    marginBlockStart: 0,
    marginBottom: 15,
lineHeight:"21px",
marginTop:5,
    fontSize: 18,
  },
  mainDiv: {
    padding: 25,
    paddingTop: 25,
marginTop:20,
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 12,
    color: "#172A44",
    fontWeight: 500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight: 25,
  },
  Image: {
    width: "50vw",
    height: "50vw",
  },
  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },
  Banner: {
    position: "relative",
    width: "100%",
    height: "50vw",
    background: `url(${ProfileBanner})`,
    backgroundColor: "#fafafa",
    borderRadius: "0px 0px 22px 22px",
  },
  bannerIcon: {
    position: "absolute",
    top: "20vw",
    left: "43vw",
    fontSize: 50,
  },
  Avatar: {

    width: 80,
    height: 80,
  

     border: "0px solid white",
  },
  AvatarPosition: {
    position: "absolute",
    bottom: -35,

    left: 30,

    
  },
  city: {
    fontSize: "16px",

    fontFamily: "Proxima Nova",
    color: "#007EA0",
    paddingTop: 15,
  },
  links: {
    display: "flex",
    flex: 1,
    fontSize: "16px",
    color: "#007EA0",
    marginTop: 8,
    flexDirection: "row",
    alignItems: "center",
  },
  para: {
    fontSize: "16px",
    lineHeight: "24px",

    color: "#172A44",
  },

  bioText: {
    fontSize: "16px",
    lineHeight: "24px",
    color: "#172A44",
    marginTop: 10,
  },
  textLight: {
    fontFamily: "Proxima Nova",
    fontStyle: "normal",
    fontWeight: "normal",
    fontAize: "16px",
    lineHeight: "29px",
    /* or 181% */

    color: "#172A44",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [userData, setUserData] = useState({
    name: "",
    profilePic: "",
    category: [],
    banner: null,
    location: "in",
    bio: null,
  });
  const [programs, setPrograms] = useState([]);
  const [viewAll,setViewAll]=useState(false);
  useEffect(() => {
    fetchUser(props.id).then((user) => {
      setUserData(user);
    });

    fetchPrograms(props.id).then((programs) => {
      console.log(programs);
      setPrograms(programs);
    });
  }, [props.id]);

  console.log()
  return (
    <Container>
      <Content>
        <Navbar style={{ backgroundColor: "rgba(0,0,0,0)" }} />
        <div
          className={classes.Banner}
          style={{
            backgroundImage: `url(${userData.banner})`,
            backgroundSize: "cover",
          }}
        >
          {!userData.banner && <Camera className={classes.bannerIcon} />}
          <Avatar
            className={classes.Avatar}
            src={userData.profilePic }
            
            userId={props.id}
            AvatarPosition={classes.AvatarPosition}
          ></Avatar>
        </div>
        <div className={classes.mainDiv}>
          <span className={classes.title}>{userData.name}</span>
          <Muted
            style={{ fontFamily: "Proxima Nova", textTransform: "capitalize" }}
          >
            {userData.expertise}
          </Muted>
          <div style={{}} className={classes.bioText}>
            {userData.bio ? userData.bio : "No bio found"}
          </div>
          <div style={{ marginTop: 10 }}>
            <span className={classes.city}>
              <Location style={{ fontSize: 14, marginRight: 5 }} />
              {getLocation(userData.location)}
            </span>
          </div>
          {userData.links &&
            userData.links.map((link) => (
              <Grid item xs={12}>
                <div className={classes.links}>{link}</div>
              </Grid>
            ))}
       
         { userData._id!==props.Profile._id&&<Button
            variant="outlined"
            fullWidth
            
            style={{ marginTop: 25, marginBottom: 25 }}
            size="sm"
            onClick={() =>props.history.push({pathname:`/chat/dt/${userData._id}`,state:{textvar:"hey"}})}
          >
            {" "}
            <b>Message</b>
          </Button>}

      

          <Grid container spacing={2} justify="center" alignItems="center">
          {programs.length > 0 &&!viewAll?(
              <Grid item xs={12}>
                <span className={classes.title2}>Programs</span>
                <br />

                {
                  <Grid
                    container
                    spacing={2}
                    style={{ marginTop: 25, marginBottom: 5 }}
                  >
                    {programs.length > 0 && (
                      <Grid item xs={6}>
                        <Workout2
                          {...programs[0]}
                          onClick={() =>
                            props.history.push(
                              `/common/programDetails/${programs[0]._id}`
                            )
                          }
                        />
                      </Grid>
                    )}

                    {programs.length > 1 && (
                      <Grid item xs={6}>
                        <Workout2
                          {...programs[1]}
                          onClick={() =>
                            props.history.push(
                              `/common/programDetails/${programs[0]._id}`
                            )
                          }
                        />
                      </Grid>
                    )}
                  </Grid>
                }

                {programs.length > 2 && (
                  <div
                  style={{
                    display: "flex",
                    flexDirection: "row",
                    justifyContent: "flex-end",
                    alignItems: "center"
                  }}
                  >
                    <Typography
                    onClick={() =>setViewAll(true)}
                      align="right"
                      color="primary"
                      gutterBottom
                      variant="subtitle2"
                      style={{ fontSize: 14, fontWeight: "bold" ,marginBottom:0}}
                    >
                      View more{" "}
                    </Typography>
                    <ArrowForwardIosIcon color="primary" style={{fontSize:18}}/>
                  </div>
                )}
              </Grid>
            ): 
            
            <Grid item xs={12}>
            <span className={classes.title2}>Programs</span>
    
<br/>
            
              <Grid
                container
                spacing={2}
                style={{marginTop: 25,  marginBottom: 5 }}
              >
                {programs.map(item =>{return(
 <Grid item xs={6}>
 <Workout2
   {...item}
   onClick={() =>
     props.history.push(
       `/common/programDetails/${programs[0]._id}`
     )
   }
 />
</Grid>
                )}) 
                 
                }

                </Grid>
                </Grid>
            
            
            }
           
          </Grid>
        </div>
      </Content>
    </Container>
  );
}
