export default function Screen2(props) {
  const classes = useStyles();
  const userFlag = useRef();

  const [location,setLocation]=useState(props.Profile.location)
const changeLocation=(country)=>{


  setLocation(country)

  
}

const handleNext=()=>{
 
  props.updateProfile({location:location}).then((res)=>{
    props.history.goBack()
  })


}

  return (
    <Container>
     <Header button={!props.editmode&&<Button onClick={()=>props.history.replace("/profile/profile-preview")}>Skip</Button>} />

      <Content flex>
  <span className={classes.title}>{props.editmode?"Update location":"Location"}</span>
        <p className={classes.secondary}>This will help people in your area find to discover you.</p>
        <div className={classes.mainDiv}>
            <div className={classes.label}>
                Choose location
            </div>
        <ReactFlagsSelect
    
        onSelect={changeLocation}
        defaultCountry={location}
    searchable={true}
    searchPlaceholder="Search for a country" />
        </div>
      </Content>
      <Footer actionButton>
        <Button
         onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          
        >
         Save
        </Button>
      </Footer>
    </Container>
  );
}
