import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"
import DoneAllIcon from '@material-ui/icons/DoneAll';
import moment from "moment"
import Divider from "@material-ui/core/Divider"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",
    display: "flex",
    flexDirection: "row",
 
  fontFamily: "Proxima nova",
  boxSizing: "border-box",

paddingTop:25,
paddingBottom:5,
borderRadius:10,

  },

  white:{
    background:"#fff",
  
  }
,
  content:{
      display:"flex",
      flexDirection:"column",
      flex:1,
      justifyContent:"center",
      marginLeft:10
  },


  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    display:"flex",
    flexDirection:"column",
    alignItems:"center",
    justifyContent:"center"
    
    
  },

 icon:{
fontSize: 60
 },
  title:{ 
     
    color: "#172A44",
    
      fontSize:16,
    display: "inline",
    textTransform:"capitalize",
    lineHeight: "20px"
    },

  images:{
    display: "flex",
     width: "100%",
     flexDirection:"row",
    
  }
,

image:{
 width:"50%",
 
marginTop:10,
borderRadius: "12px",



},
inside:{
  width:"90%",

paddingTop:"80%",
  borderRadius: "12px",
   background:"black",
   
},
time:{
fontSize: 10,
marginLeft:5,
color: "#172A44",
}
,
  subTitle:{
    fontWeight: "normal",
    fontFamily:"Proxima Nova",
    fontStyle:"normal",
    fontSize: 14,
    overflow: "hidden",
   textOverflow: "ellipsis",
   textTransform:"capitalize",
   marginTop:5,
   display: "box",
  lineClamp: 2,/* number of lines to show */
 boxOrient: "vertical",
    lineHeight: "18px",
  
    color: "#707C97"
  },
  small:{
    width:"auto"
  },
  detailsCount:{
    display: "flex",
    flexDirection:"column",
    alignItems:"center",
    justifyContent:"center"
  },
  count:{
    color:"white",
    backgroundColor:"#007EA0",
  display: "flex",
  flexDirection:"column",
  justifyContent:"center",
  alignItems:"center",
    borderRadius:"50%",
    width:25,
    height:25,
    fontSize:12
  }
  

}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images,
IconAv

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
    [classes.white]:white
})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  <>
      <div className={mainDiv}>
          <div className={classes.avatar}>

        {IconAv}
        </div>
        <div className={classes.content}>
            <div className={classes.title}>
           {Title} <span className={classes.time}>{Time}</span>

            </div>
            <div className={classes.subTitle}>
            {Text}
            </div>

             {/* <div className={classes.images}>
               {Images.map(item =>( <div className={classes.image}>
<div className={classes.inside}
style={{backgroundImage: "url(" + item + ")",backgroundSize:"cover"}}
></div>
              </div>))}
             
              
            </div>  */}
          
        </div>
        <div className={classes.detailsCount}>
         <div style={{marginBottom:4,color:"rgba(23,42,68,0.75)",fontSize:10}}> {moment(props.createdAt).format('LT')}</div>
{props.count==0&&<DoneAllIcon style={{color:"#1E98BE",fontSize:18}}/>}
          {props.count>0&&<div className={classes.count}> {props.count}</div>}
             

            </div>
</div>
<Divider style={{background:"#ECEEEF"}} variant="inset"  />
</>

 
  );
});


export default AnnouncCard;
