import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import WorkoutCalender from "../Screens/clienttabs/WorkoutCallender"
import ExercisePlayer from "../Screens/clienttabs/ExerciseView"
import {connect} from "react-redux"

import {updateFeedback} from "../store/actions/feedback"

class DailyExercise extends Component {
    state={
currentWeek:0,
currentDay:0,
currentExercise:0


    }


    componentDidMount=()=>{
      
    }

    startExercise=(index)=>{
this.setState({currentExercise:index})
this.props.history.push(`${this.props.match.path}/play`)
    }

    render() {
        
        return (
            <div>
            
                   <Route exact  path={`${this.props.match.path}/`} render={()=><WorkoutCalender {...this.props} {...this.state} setState={(data)=>this.setState({...data})} startExercise={this.startExercise}  />} />
                   <Route exact  path={`${this.props.match.path}/play`} render={()=><ExercisePlayer {...this.props} {...this.state} setState={(data)=>this.setState({...data})} />} />
                
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
       
        Profile:state.Profile,
        AtheletePlan:state.AtheletePlan
    }
}

export default connect(mapStateToProps,{updateFeedback})(DailyExercise)