import React,{useState} from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Progress from "components/Progress/CircularProgree" 
import axios from "utils/axios"
import api from "utils/api"
import IconButton from "@material-ui/core/IconButton"
import ReactPlayer from 'react-player'
const uuidv4 = require("uuid/v4")
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position:"relative",
    backgroundSize: "cover",
    width: "100%",
    flexDirection:"column",
   fontFamily: "Lato",
    display:"flex",
    height: "100%",
    justifyContent:"center",
    alignItems:"center",
    border: "3px solid rgba(0, 126, 160, 0.25)",
boxSizing: "border-box",
borderRadius: "22px",

overflow:"hidden"
  },

  IconContainer:{
    width: "100%",
    height:"100%",
    position:"absolute",
    flexDirection:"column",
    fontFamily: "Lato",
     display:"flex",
zIndex:200,

     justifyContent:"center",
     alignItems:"center",
 
  },

  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    display:"flex",
    flexDirection:"column",
    alignItems:"center",
    justifyContent:"center",
    fontFamily: "Lato",
    
  },

 icon:{
marginBottom:"5px",


 },
  title:{ 
     
  
      fontFamily: "Proxima Nova",

      fontWeight:"bold",color:"#007EA0",fontSize:14,marginTop:10
    },

    small:{
        fontSize:10,
        marginTop:0
    },

    selected:{
        color:"#007EA0"
    },

    selectedContainer:{
        border: "2px solid #007EA0",
        background: "#E4F0F4"

    },

    Progress:{
      position:"absolute",
      bottom:10,
      right:10,
      background:"#fffff",
      borderRadius:"50%",
      zIndex:2000
    }

}));

const TitleSub = React.forwardRef((props, ref) => {


const {selected, 
Title, 
text, 
Icon,
sm,
white

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
    [classes.white]: white
})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected,
        [classes.small]:sm,
        
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
    const [val,setVal]=useState(0)
    const [upload,setUpload]=useState(false)
    const [file,setFile]=useState(props.file)
  const id=uuidv4()

  const uploadImage=(e)=>{
    setUpload(true)
    const form = new FormData();
   
    form.append("rsfile", e.target.files[0]);
    axios.post(`${api.protocol}${api.baseUrl}${api.UploadSingleFile}`, form,
   { onUploadProgress: progressEvent => {
      let uploadPercentage = parseInt(
        Math.round((progressEvent.loaded / progressEvent.total) * 100)
      );
     setVal(  uploadPercentage)
      
     
    }}
    )
      .then((result) => {
     setUpload(false)
     setFile(result.data.Location)
 
          props.handleSuccess(result.data.Location)
    
      })
      .catch((error) => {
        props.handleError(error)
      })
  }


  return (
    <>
  <input type={"file"} onChange={uploadImage} id={id} style={{display:"none"}} accept={props.image?"image/x-png,image/gif,image/jpeg,image/png,image/jpg":"video/*" } />
      <div className={mainDiv} style={props.image?{backgroundImage: `url(${file})`,backgroundSize: "cover"}:{}}>
      
<div className={classes.IconContainer}>
         <IconButton size={props.sm?"small":"medium"} className={icon} onClick={()=>!props.noAction&&document.getElementById(id).click()}>
        {Icon(icon)}
          </IconButton>
          {!props.file&&<span className={title}>
            {Title}
          </span>}
          </div>
         
     {upload&& <div className={classes.Progress}>
        <Progress value={val}/>
      </div>}

      {props.video&&
      <ReactPlayer 
      autoPlay
      playing={true}
      style={{width: "100%",height:"auto",borderRadius:10,overflow: "hidden",position:"absolute",top:0}}
      width= "100%"
      height= "100%"
      url={file} />
      
      }

        </div>


</>
 
  );
});


export default TitleSub;
