import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";

// @material-ui/icons
import Face from "@material-ui/icons/Face";
import Chat from "@material-ui/icons/Chat";
import Build from "@material-ui/icons/Build";
import DietIcon from "assets/svg/DietIcon"
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import BottomNav from "components/BottomNav";
import NumberSelector from "components/CustomTabs/NumberTabs";
import styles from "assets/jss/material-kit-react/views/componentsSections/tabsStyle.js";
import InfoBox from "components/InfoBox";
import InsAthlete from "components/Card/InsAthlete";
import AnnouncCard from "components/Card/announcement";
import ChatCard from "components/Card/Chat"
import Button from "components/CustomButtons/Button.js"
import UploadCard from "components/Card/UploadCard"
import Camera from "assets/svg/Camera"
import IconButton from '@material-ui/core/IconButton';
import AddIcon from "assets/svg/AddIcon"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar'
import Divider from '@material-ui/core/Divider';
import InboxIcon from '@material-ui/icons/Inbox';
import DraftsIcon from '@material-ui/icons/Drafts';
import WeightLifting from "assets/svg/WeightLifting"
import ArrowRight from "assets/svg/ArrowRight"
import ListItemSecondaryAction from '@material-ui/core/ListItemSecondaryAction';
import Avatar from '@material-ui/core/Avatar'
import Exit from "assets/svg/Exit"
import Info from "assets/svg/Info"
import Bulb from "assets/svg/Bulb"
import Gear from "assets/svg/Gear"
import Card from "assets/svg/Card"
import Stats from "assets/svg/Stats"
import ProfileIcon from "assets/svg/Profile"
import ExerciseLib from "assets/svg/ExerciseLib"
import {withRouter} from "react-router-dom"
import {connect } from "react-redux"
import {updateProfile} from "store/actions/Profile"
const useStyles = makeStyles({
   primary: {
       fontFamily: "Proxima Nova",
       fontSize:16
   },
   root:{ 
       padding:15
   },
   icon:{
       fontSize:28,
       color:"#172A44"
   },
   mainHeader:{
display:"flex",
width:"100%",
marginTop:10,

flexDirection:"column"
   },
   mainContent:{
display: "flex",
flexDirection:"column",

justifyContent:"flex-start",
width:"100%",
padding:10

   },

   avatar:{
       width:70,
       height:70,
       marginRight:20
   },
   title:{
       fontFamily: "Proxima Nova",
       color:"#172A44",
       fontSize:24,
       textTransform:"capitalize",
       display:"flex",
       flexDirection:"column",
   }

});

 function SectionTabs(props) {
  const classes = useStyles();
  return (
 
    
<div style={{backgroundColor:"#fff",padding:20,width:"70vw",paddingTop:0}}>
<div className={classes.mainHeader}>
    <div className={classes.mainContent}>
<Avatar className={classes.avatar} src={props.Profile.profilePic}></Avatar>

<h2 className={classes.title}>{props.Profile.name}
<span style={{fontWeight:"normal",fontSize:14,fontColor:"#747F8F",lineHeight:"14px"}}>Figgs ID ({props.Profile.figgsId})</span>

</h2>


    </div>
  

    {/* <Button bold variant="contained" fullWidth={false} style={{width:"50%",marginLeft:10}}
    onClick={()=>props.history.push("/profile/profile-preview")}
    >View Profile</Button> */}
</div>
      <List component="nav" aria-label="main mailbox folders">
      <ListItem button classes={{root:classes.root}} onClick={()=>props.history.push("/profile/profile-preview")}>
          <ListItemIcon >
            <ProfileIcon className={classes.icon} />
          </ListItemIcon>
          <ListItemText primary="View profile" classes={{primary:classes.primary}} />
        </ListItem>
        <ListItem button classes={{root:classes.root}} onClick={()=>props.updateProfile({type:"Athlete"})}>
          <ListItemIcon >
            <WeightLifting className={classes.icon} />
          </ListItemIcon>
          <ListItemText primary="Become athlete" classes={{primary:classes.primary}} />
        </ListItem>
        <ListItem button classes={{root:classes.root}}
        onClick={()=>props.history.push("/library")}
        >
          <ListItemIcon
          
          >
            <ExerciseLib className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Exercise Library" classes={{primary:classes.primary}}  />
        </ListItem>
      </List>
      <Divider />
      <List component="nav" aria-label="main mailbox folders">
        <ListItem button classes={{root:classes.root}}>
          <ListItemIcon>
            <Card className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Payment & Cards" classes={{primary:classes.primary}} />
        </ListItem>
        {/* <ListItem button classes={{root:classes.root}}>
          <ListItemIcon>
            <Stats className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Statistics" classes={{primary:classes.primary}} />
        </ListItem> */}
        <ListItem button classes={{root:classes.root}}
             onClick={()=>props.history.push("/account-settings")}
        >
          <ListItemIcon>
            <Gear className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Account Settings" classes={{primary:classes.primary}} />
        </ListItem>
      </List>
      <Divider />
      <List component="nav" aria-label="main mailbox folders">
        <ListItem button classes={{root:classes.root}}>
          <ListItemIcon>
            <Info className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Help and Support" classes={{primary:classes.primary}} />
        </ListItem>
        <ListItem button classes={{root:classes.root}}
        onClick={()=>props.history.push("/instructor/feedback")}
        >
          <ListItemIcon>
            <Bulb className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Write us Feedback" classes={{primary:classes.primary}} />
        </ListItem>
      </List>
      <Divider />
      <List component="nav" aria-label="main mailbox folders">
        <ListItem button classes={{root:classes.root}} onClick={()=>props.signOut()}>
          <ListItemIcon>
            <Exit className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Sign out" classes={{primary:classes.primary}} />
        </ListItem>
       
      </List>
    </div>
 
  );
}
export default connect(null,{updateProfile})(withRouter(SectionTabs))