import React,{useState} from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Progress from "components/Progress/CircularProgree" 
import axios from "utils/axios"
import api from "utils/api"
import IconButton from "@material-ui/core/IconButton"
import Grid from "@material-ui/core/Grid"
import Badge from "@material-ui/core/Badge"
import Lightbox from 'react-image-lightbox';
import 'react-image-lightbox/style.css'
import CancelIcon from '@material-ui/icons/Cancel';
import ReactPlayer from 'react-player'
const uuidv4 = require("uuid/v4")
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position:"relative",
    backgroundSize: "cover",
    paddingBottom:"78%",
    width: "100%",
    flexDirection:"column",
   fontFamily: "Lato",
    display:"flex",
    height: "100%",
    justifyContent:"center",
    alignItems:"center",
    border: "3px solid #E4F0F4",
boxSizing: "border-box",
borderRadius: "12px",
position:"relative",
overflow:"hidden"
  },


  A4Doc:{
    paddingBottom:"100%",
    background: "#F9FCFD",
border: "1px solid rgba(0, 126, 160, 0.5)",
boxSizing: "border-box",
borderRadius: "11px"
  }
,
  IconContainer:{
    width: "100%",
    height:"100%",
    position:"absolute",
    flexDirection:"column",
    fontFamily: "Lato",
     display:"flex",
zIndex:200,
     justifyContent:"center",
     alignItems:"center",
 
  },

  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    display:"flex",
    flexDirection:"column",
    alignItems:"center",
    justifyContent:"center",
    fontFamily: "Lato",
    
  },

 icon:{

background:"rgba(255,255,255,0.2)"

 },
  title:{ 
     
  
      fontFamily: "Proxima Nova",

      fontWeight:"bold",color:"#172A44",fontSize:14,
    },

    small:{
        fontSize:10,
        marginTop:0
    },

    selected:{
        color:"#007EA0"
    },

    selectedContainer:{
        border: "2px solid #007EA0",
        background: "#E4F0F4"

    },

    Progress:{
    
      background:"#fffff",
      borderRadius:"50%",
      zIndex:2000
    }
    ,
    Badge:{
      position:"absolute",
      top:0,
      right:0,
    
      zIndex:10000
    }

}));

const TitleSub = React.forwardRef((props, ref) => {


const {selected, 
Title, 
text, 
Icon,
sm,
white,
A4

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
    [classes.white]: white,
    [classes.A4Doc]:A4
})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected,
        [classes.small]:sm,
        
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
    const [val,setVal]=useState(0)
    const [upload,setUpload]=useState(false)
    const [file,setFile]=useState([...props.files])
    const [photoIndex,setIndex]=useState(0)
    const [lightbox,setLightBox]=useState(false)
  const id=uuidv4()


const openLightBox=(index)=>{
  setIndex(index)
  setLightBox(true)
}

  const uploadImage=(e)=>{
    if(! e.target.files[0])
    return false
    setUpload(true)
    const form = new FormData();
   
    form.append("rsfile", e.target.files[0]);
    axios.post(`${api.protocol}${api.baseUrl}${api.UploadSingleFile}`, form,
   { onUploadProgress: progressEvent => {
      let uploadPercentage = parseInt(
        Math.round((progressEvent.loaded / progressEvent.total) * 100)
      );
     setVal(  uploadPercentage)
      
     
    }}
    )
      .then((result) => {
     setUpload(false)
   setFile([...file,result.data.Location])

   props.handleUpdate([...file,result.data.Location])
         // props.handleSuccess(result.data.Location)
    
      })
      .catch((error) => {
      //  props.handleError(error)
      })
  }

  const deleteImage=(index)=>{
    let files=[...file]
    files.splice(index,1)
    setFile(files)
  props.handleUpdate(files)
  }


  return (
    <>

{lightbox
&&

<Lightbox
  mainSrc={file[photoIndex]}
  nextSrc={file[(photoIndex + 1) % file.length]}
  prevSrc={file[(photoIndex + file.length - 1) % file.length]}
  onCloseRequest={() =>  setLightBox(false)}
  onMovePrevRequest={() =>
    setIndex((photoIndex + file.length - 1) % file.length)
   
  }

  onMoveNextRequest={() =>
    setIndex((photoIndex + 1) % file.length)
  
  }


/>

}







  <input type={"file"} onChange={uploadImage} id={id} style={{display:"none"}} accept={"image/x-png,image/gif,image/jpeg,image/png,image/jpg" } />
  <Grid container spacing={1} >
{file.map((item,index)=>{
  return(
  
<Grid item xs={4} >
<Badge
    overlap="circle"
    anchorOrigin={{
      vertical: 'top',
      horizontal: 'right',
    }}
    style={{width: "100%",height:"100%"}}

    badgeContent={!props.ViewMode&&<CancelIcon   onClick={()=>!props.ViewMode&&deleteImage(index)} style={{fontColor:"#fff",backgroundColor:"#fff",borderRadius:"50%"}} />}
  >
<div className={mainDiv} onClick={()=>openLightBox(index)} style={{backgroundImage: `url(${item})`,backgroundSize: "cover"}}>


</div>
</Badge>
</Grid>

  )
})}
    {!props.ViewMode&&<Grid item xs={4} >
    <div className={mainDiv} style={props.image?{backgroundImage: `url(${file})`,backgroundSize: "cover"}:{}}>
      <div className={classes.childDiv}>
      <div className={classes.IconContainer}>
       {!upload? <>
               <IconButton size={props.sm?"small":"medium"} className={icon} onClick={()=>!props.noAction&&document.getElementById(id).click()}>
              {Icon(icon)}
                </IconButton>
                {!props.file&&<span className={title}>
                  {Title}
                </span>}
      </>:  <div className={classes.Progress}>
              <Progress value={val}/>
            </div>}
                </div>
               </div>
         
      
      
              </div>
    </Grid>}
  </Grid>
      


</>
 
  );
});


export default TitleSub;
