import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import Icon from "@material-ui/core/Icon";
// @material-ui/icons
import Search from "@material-ui/icons/Search";
import Email from "@material-ui/icons/Email";
import Face from "@material-ui/icons/Face";
import AccountCircle from "@material-ui/icons/AccountCircle";
import Explore from "@material-ui/icons/Explore";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Header from "components/Header/Header.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import CustomDropdown from "components/CustomDropdown/CustomDropdown.js";
import Button from "@material-ui/core/Button";
import Toolbar from "@material-ui/core/Toolbar"
import AppBar from "@material-ui/core/AppBar"
import IconButton from "@material-ui/core/IconButton"

import image from "assets/img/bg.jpg";
import profileImage from "assets/img/faces/avatar.jpg";
import ArrowRight from "assets/svg/ArrowRight"
import styles from "assets/jss/material-kit-react/views/componentsSections/navbarsStyle.js";
import Typography from "@material-ui/core/Typography"

const useStyles = makeStyles((theme) => ({
  root: {
    flexGrow: 1,
  },
  menuButton: {
    marginRight: theme.spacing(3),
    
  },
  title: {
    flexGrow: 1,
  },
}));
export default function SectionNavbars(props) {
  const classes = useStyles();
  return (
    
        <GridContainer spacing={4}>
          <GridItem xs={12}>
            <Typography variant="h4">Navigation</Typography>
          </GridItem>
          <GridItem xs={12} sm={12} md={6}>
          <AppBar position="static" style={{backgroundColor:"#fff",boxShadow:"none"}}>
  <Toolbar>
    <IconButton edge="start" className={classes.menuButton} color="inherit" aria-label="menu">
      <ArrowRight color={"primary"} style={{transform:"rotate(180deg)"}} />
    </IconButton>
  <Typography style={{flexGrow:1}}></Typography>
  {props.button}
  </Toolbar>
</AppBar>
           </GridItem>
          </GridContainer>
  );
}
