import React, { Component, useState, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Typography from "@material-ui/core/Typography";
import {
  createSubscription,
  approveSubscription,
  createOrder,
  approveOrder,
  addFreeOrder
} from "store/actions/payments";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import PriceCard from "components/Card/priceCard";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import ListItemSecondaryAction from "@material-ui/core/ListItemSecondaryAction";
import Divider from "@material-ui/core/Divider";
import ProfileImg from "assets/img/screens/profile.png";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import Grid from "@material-ui/core/Grid";
import Chip from "@material-ui/core/Chip";
import Avatar from "@material-ui/core/Avatar";
import Camera from "assets/svg/Camera";
import ChipInput from "components/CustomInput/ChipInput";
import Checkbox from "components/CheckBox";
import DateFnsUtils from "@date-io/date-fns";
import "date-fns";
import MomentUtils from "@date-io/moment";
import {
  MuiPickersUtilsProvider,
  KeyboardTimePicker,
  KeyboardDatePicker,
} from "@material-ui/pickers";
import InputAdornment from "@material-ui/core/InputAdornment";
import IconButton from "@material-ui/core/IconButton";
import CalendarTodayIcon from "@material-ui/icons/CalendarToday";
import "react-phone-input-2/lib/style.css";
import CancelIcon from "@material-ui/icons/Cancel";
import AddIcon from "@material-ui/icons/Add";
import PublishIcon from "@material-ui/icons/Publish";
import AddFolder from "assets/svg/addFolder";
import Subscription from "assets/svg/Subscription";
import OneTime from "assets/svg/OneTime";
import Select from '@material-ui/core/Select';
import PaypalIcon from "assets/svg/Paypal";
import {Helmet} from "react-helmet"
import FormControl from '@material-ui/core/FormControl';
import MenuItem from '@material-ui/core/MenuItem';

import ExpandMoreOutlinedIcon from '@material-ui/icons/ExpandMoreOutlined';
import { getSentPrograms, addProgram } from "store/actions/common";
const useStyles = makeStyles((theme) => ({
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    fontSize: 24,
    marginBlockStart: 0,
    
    color:"#172A44",
    paddingTop: 10,
    paddingLeft: 25,
  },
  mainDiv: {
    padding: 25,
    paddingTop: 15,

    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontFamily: "Proxima Nova",
    paddingLeft: 3,
    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },

  image: {
    width: "100%",
    paddingTop: "60%",
    borderRadius: 16,
    backgroundColor: "grey",
  },

  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },

  Avatar: {
    position: "absolute",
    bottom: -25,
    width: 60,
    height: 60,
    left: 30,
  },

  label: {
    fontFamily: "Proxima Nova",
    color: "#172A44",
    fontSize: "18px",
lineHeight: "19px",
    fontWeight: "bold",
  },
  prDetails: {
    fontFamily: "Proxima Nova",
    color: "#172A44",
    fontSize: "18px",
    marginTop:10,

    lineHeight: "22px",
   
  },

  secondary: {
    fontFamily: "Proxima Nova",
   

    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },
  AvatarImage:{
    width: 45, height:45,
  
  },
  AvatarPosition:{
    position: "relative",
  },
  Dropdown:{
    paddingBottom:15,
   
  }
}));

export default function Screen2(props) {
  const classes = useStyles();

  const [data, setData] = useState({
    Amount: 0,
    Program: {
      BannerImage: null,
      PaymentType: null,
      Title: "My fitness Program",
    },
  });

  const [sharedId,setSharedId]=useState(null)

  useEffect(() => {

    if(props.Profile.type&&props.Profile.type!=="Athlete"){
      props.updateProfile({type:"Athlete"})
    }

console.log(props)
props.getSpecificPublicProgram(props.id).then(data => {
    setData({ Amount:data.Price,Program:data})
    if(props.token)
    props.sharedProgramData(props.id).then(shareId=>{
      setSharedId(shareId)

   
   
            if(data.PaymentType=="Subscription"){
              window.paypal
                .Buttons({
                  style: {
                    layout: "horizontal",
                    color: "blue",
                    height: 55,
                  },
                  createSubscription: function (data, actions) {
                    return createSubscription(shareId).then((result) => {
                      return result;
                    });
                  },
      
                  onApprove: function (data, actions) {
                    console.log(data);
                    approveSubscription(data.subscriptionID)
                      .then(() => {
                        props.updateFeedback({
                          loading: false,
                          snackbar: true,
                          message: "Subscription Activated Successfully",
                          severity: "success",
                        });
                        props.history.replace("/athlete/my-programs");
                      })
                      .catch((err) => {
                        props.updateFeedback({
                          loading: false,
                          snackbar: true,
                          message:
                            "Unable to activate subscription please contact support",
                          severity: "info",
                        });
                      });
                  },
      
                  onError:function(err){
                    // props.updateFeedback({
                    //   loading: false,
                    //   snackbar: true,
                    //   message:
                    //     "Unable to process please try again",
                    //   severity: "error",
                    // })
              
                  }
                })
                .render("#paypal-button-container");
            }
      else
      {
        window.paypal
        .Buttons({
          style: {
            layout: "horizontal",
            color: "blue",
            height: 55,
          },
          createOrder: function (data, actions) {
            return createOrder(shareId).then((result) => {
      
              return result;
      
            });
          },
      
          onApprove: function (data, actions) {
            console.log(data);
            approveOrder(data.orderID)
              .then(() => {
                props.updateFeedback({
                  loading: false,
                  snackbar: true,
                  message: "Plan Activated Successfully",
                  severity: "success",
                });
                props.history.replace("/athlete/my-programs");
              })
              .catch((err) => {
                props.updateFeedback({
                  loading: false,
                  snackbar: true,
                  message:
                    "Unable to activate plan please contact support",
                  severity: "info",
                });
              });
          },
      
          onError:function(err){
            // props.updateFeedback({
            //   loading: false,
            //   snackbar: true,
            //   message:
            //     "Unable to process please try again",
            //   severity: "error",
            // })
      
          }
        })
        .render("#paypal-button-container");
      }
      


    })

})



    // getSentPrograms(props.id).then((resData) => {
  
    // });
  }, [props.id]);

  const addnewOrder = (id) => {
console.log(props.history)
if(!props.token){
props.history.push(`/onboarding/account-details`,{return:`/public/sharedProgram/${props.id}`,accountType:"Athlete"})
}
else{
  addFreeOrder(id).then((res) =>{
    props.updateFeedback({
      loading: false,
      snackbar: true,
      message: "Program Acded Successfully",
      severity: "success",
    });
    props.history.replace(`${props.match.path}/athlete/my-programs`)
  });
}
    
    



  };




  return (
    <Container>
      <Header />
<Helmet>
  <title>{data.Program.Title}</title>
<meta property="og:title" content={data.Program.Title} />
<meta property="og:description" content={data.Program.Description} />
<meta property="og:image" content={data.Program.BannerImage
                          ? data.Program.BannerImage
                          : "https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"} />
<meta property="og:url" content="http://euro-travel-example.com/index.htm" />
</Helmet>
      <Content>
        <div className={classes.title}>Purchase</div>

        <div className={classes.mainDiv}>
          <Grid container spacing={3} justify="center" alignItems="center">
            <Grid item xs={12}>
              <Grid container style={{ marginTop: 5 }}>
                <Grid item xs={5}>
                  <div
                    className={classes.image}
                    style={{
                      backgroundImage: `url(${
                        data.Program.BannerImage
                          ? data.Program.BannerImage
                          : "https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"
                      })`,
                      backgroundSize: "cover",
                    }}
                  ></div>
                </Grid>
                <Grid item xs={6} style={{marginLeft: 15}}>
                <div className={classes.prDetails}>{data.Program.Title}</div>
                </Grid>
               
               
              </Grid>
            
            </Grid>
           <Divider style={{width: "100%",marginTop:3,marginBottom:13,backgroundColor:"#ECEEEF"}}/>

            <Grid item xs={12}>
              <span className={classes.label}>Message</span>
            
              <div className={classes.secondary} style={{marginTop:10}}>
                {data.Program.GreetingMessage
                  ? data.Program.GreetingMessage
                  : "No message provided by instructor"}
              </div>
             
            </Grid>
            <Divider style={{width: "100%",marginTop:3,marginBottom:3,backgroundColor:"#ECEEEF"}}/>
            <Grid item xs={12}>
              <span className={classes.label}>Program by</span>
              <div style={{display: "flex",flexDirection:"row",flex:1,  marginTop:15}}>
            <Avatar  className={classes.AvatarImage} imgProps={{style:{width: "100%",height: "auto",objectFit: "fill"}}} src={data.Program.createdBy?data.Program.createdBy.profilePic:""}/>
              <div className={classes.secondary} style={{dipslay:"flex",flex:1,lineHeight:"20px",flexDirection:"column",marginLeft:15,alignItems:"center",textTransform:"capitalize"}}>
                {data.Program.createdBy
                  ? data.Program.createdBy.name
                  : "N/A"}

                  <div style={{color:"#007EA0",lineHeight:"20px"}}>View profile</div>
              </div>
              </div>
            </Grid>
            <Divider style={{width: "100%",marginTop:3,marginBottom:13,backgroundColor:"#ECEEEF"}}/>
            {data.Amount !== null && Number(data.Amount) > 0 && (
              <Grid item xs={12}>
                <span className={classes.label}>Payment model</span>
               

                <Grid container style={{ marginTop: 10 }} spacing={1}>
                  <Grid item xs={12} style={{ display: "flex" }} >
                    <Typography style={{ color: "#172A44", size: 16 }}>
                      Price :
                    </Typography>
                 
                    &nbsp;{" "}
                    <Typography color={"primary"} >$ {data.Amount}</Typography>
                  </Grid>

                  <Grid item xs={12} style={{ display: "flex" }}>
                    <Typography style={{ color: "#172A44", size: 16 }}>
                      Type :
                    </Typography>
                    &nbsp;{" "}
                    <Typography color={"primary"}>
                      {data.Program.PaymentType}
                    </Typography>
                  </Grid>
                </Grid>
            
              </Grid>
            )}

            {data.Amount?<Grid item xs={12} >
              <span className={classes.label} style={{fontSize:16}}>Payment method</span>
            
         
              <List >
                <ListItem style={{ paddingLeft: 0, paddingRight: 2 }}>
                <FormControl fullWidth>
                <Select
    
     IconComponent={ExpandMoreOutlinedIcon}
          value={"Paypal"}
          // onChange={handleChange}
     classes={{root:classes.Dropdown}}
          inputProps={{
            style:{borderBottom:"1px solid white"},
            name: 'age',
            id: 'age-native-simple',
          }}
        >
          
          <MenuItem value={"Paypal"}><div style={{display: "flex",flexDirection:"row",alignItems:"center"}}><PaypalIcon style={{ fontSize: 25 }} />&nbsp;&nbsp;Paypal</div> </MenuItem>
       
        </Select>
        </FormControl>
                </ListItem>
              </List>


            </Grid>:null}
          </Grid>
        </div>
      </Content>
      <Footer actionButton>
       { data.Amount&&props.token?<div id="paypal-button-container"></div>:
        <Button
        onClick={()=>addnewOrder(sharedId)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button> }
      </Footer>
    </Container>
  );
}
