import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Typography from "@material-ui/core/Typography";
import UploadCard from "components/Widget/AddImages"
import { getLocation } from "utils/helpers";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import { handleuploadImage } from "utils/uploader";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from '@material-ui/core/ListItem';
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import AddIcon from "assets/svg/AddCircle";
import ProfileImg from "assets/img/screens/profile.png";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import InputBase from "@material-ui/core/InputBase";
import Divider from "@material-ui/core/Divider";
import DietPlan from "assets/svg/DietIcon"
import Calender from "assets/svg/Calender"
import Heart from "assets/svg/HeartHealth"
import Location from "assets/svg/Location";
import Grid from "@material-ui/core/Grid";

import Navbar from "components/Navbar";
import Avatar from "@material-ui/core/Avatar";
import Camera from "assets/svg/Camera";
import axios from "utils/axios";
import api from "utils/api"
import IconButton from "@material-ui/core/IconButton"
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemSecondaryAction from "@material-ui/core/ListItemSecondaryAction";
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
   textTransform:"capitalize",
   color:"#172A44",
    fontSize: "24px",
  },

  subTitle: {
    fontStyle: "normal",
    textTransform:"capitalize",
    fontWeight: "normal",
    fontSize: "16px",
    lineHeight: "20px",
    /* or 125% */
    color: "#747F8F",
  },

  mainDiv: {
    padding: 25,
    paddingTop: 35,

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 5,
    color: "#172A44",
    fontWeight: 500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
  },
  Image: {
    width: "50vw",
    height: "50vw",
  },
  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },
  Banner: {
    position: "relative",
    width: "100%",
    height: "50vw",
    backgroundColor: "rgba(23, 42, 68, 0.25)",

    borderRadius: "0px 0px 22px 22px",
  },
  bannerIcon: {
    position: "absolute",
    top: "20vw",
    left: "43vw",
    fontSize: 50,
  },
  Avatar: {
    position: "absolute",

    bottom: -25,
    width: 60,
    height: 60,
    left: 30,
    border: "5px solid white",
  },
  city: {
    fontSize:"16px",
   
       fontFamily: "Proxima Nova",
       color: "#007EA0",
       paddingTop: 10,
     },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [val, setVal] = useState(null);
  const handleNext = () => {
    axios.post(`${api.protocol}${api.baseUrl}${api.userSignup}`,{...props.Onboarding}).then((response)=>{
      props.updateFeedback({loading:false,snackbar:true,message:"Figgs account created succesfully",severity:"success"})
      props.updateOnboarding({token:response.data.token})
      localStorage.setItem("token",response.data.token)
      axios.defaults.headers.common['Authorization']=response.data.token
      props.initProfile({...response.data.userData,password:"",...response.data})
    
    
    
      props.history.push("/profile/welcome",props.location.state)
    
    })
    .catch((error)=>{
      return props.updateFeedback({loading:false,snackbar:true,message:"Unexpected error! Please try again",severity:"error"})
    })
  };

  const uploadProfilePic = (e) => {
    props.updateFeedback({ loading: true });
    handleuploadImage(e).then(
      (res) => {
        props.updateOnboarding({ profilePic: res.data.Location });
        props.updateFeedback({ loading: false });
      },
      (rej) => {
        if (rej == "size")
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Image size should be less than 5 mb",
            severity: "warning",
          });
        else
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Error in uploading image please try again later",
            severity: "warning",
          });
      }
    );
  };

  const uploadBanner = (e) => {
    props.updateFeedback({ loading: true });
    handleuploadImage(e).then(
      (res) => {
        props.updateOnboarding({ banner: res.data.Location });
        props.updateFeedback({ loading: false });
      },
      (rej) => {
        if (rej == "size")
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Image size should be less than 5 mb",
            severity: "warning",
          });
        else
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Error in uploading image please try again later",
            severity: "warning",
          });
      }
    );
  };

  const handleChange = (value, index) => {
    let arr = [...props.Onboarding.links];

    if (value) {
      arr[index] = value;
    } else {
      arr.splice(index, 1);
    }
    props.updateOnboarding({ links: arr });
  };

  const addNewLink = (e) => {
    let arr = [...props.Onboarding.links];
    if (e.target.value) {
      arr.push(e.target.value);
      props.updateOnboarding({ links: arr });
      setVal("");
    }
  };

  return (
    <Container>
      <Navbar
        navbarProps={{
          position: "fixed",
          style: { background: "none", boxShadow: "none" },
        }}
      />

      <Content>
        <div
          className={classes.Banner}
          style={{
            backgroundImage: `url(${props.Onboarding.banner})`,
            backgroundSize: "cover",
          }}
        >
          {!props.Profile.banner && (
            <Camera

              className={classes.bannerIcon}
              onClick={() => document.getElementById("banner").click()}
            />
          )}
          <input
            type="file"
            id="banner"
            onChange={uploadBanner}
            style={{ display: "none" }}
          />
          <input
            type="file"
            id="profile"
            onChange={uploadProfilePic}
            style={{ display: "none" }}
          />

          <Avatar
          style={{backgroundColor:props.Onboarding.profilePic?"#fafafa":"none"}}
            className={classes.Avatar}
            src={props.Onboarding.profilePic}
          ></Avatar>
        </div>
        <div className={classes.mainDiv}>
          <div className={classes.title}>{props.Onboarding.name}</div>

          <div className={classes.subTitle}>{props.Onboarding.expertise}</div>
   <br/>
          <div className={classes.secondary}>{props.Onboarding.type=="Instructor"?props.Onboarding.bio:props.Onboarding.healthGoals}</div>
          <div style={{ marginTop: 10 }}>
           {props.Onboarding.location&& <span className={classes.city}>
              <Location style={{ fontSize: 14,marginRight:5 }} />
              {getLocation(props.Onboarding.location)}
            </span>}
          </div>
          <br />
          {props.Onboarding.type=="Instructor"?<Grid container>
            {props.Onboarding.links.map((item, index) => {
              return (
                <Grid item xs={12}>
                  <div className={classes.link_continer}>
                    <div className={classes.link_value}>
                      <CustomInput
                       
                      
                       bottomUnderline
                     
                        
                        
        inputProps={{
          defaultValue:item,
          style:{marginTop:10,paddingTop: 1 },
          onBlur:(e) => handleChange(e.target.value, index),
          placeholder:"Add Link"
      }}
                      formControlProps={{
                        fullWidth: true,
                        
                      }}
                      />


                    </div>
                  </div>
                </Grid>
              );
            })}

            <Grid item xs={12}>
              <div className={classes.link_continer}>
                <div className={classes.link_value}>
                

<CustomInput
                       
                      
                       bottomUnderline
                     
                        
                        
        inputProps={{
          value:val,
          style:{marginTop:10,paddingTop: 1 },
          onChange:(e) => setVal(e.target.value),
          onBlur:addNewLink,
          placeholder:"Add Link"
      }}
                      formControlProps={{
                        fullWidth: true,
                        
                      }}
                      />



                </div>
              </div>
            </Grid>
          
          </Grid>:
          <Grid container>
          <Grid item xs={12}>
            <List >
                <ListItem button style={{paddingLeft:0,paddingRight:0}} onClick={() =>props.history.push(`${props.match.url}/health-info1`,props.location.state)}>
                    <ListItemIcon>
                        <IconButton style={{borderRadius:"11px",background:"#F9FCFD"}}>
                        <Heart color="primary"/>
                        </IconButton>
                   
                    </ListItemIcon>
                    <ListItemText primary="Health information" />
                    <ListItemSecondaryAction>
                        <ArrowRight color="primary"/>
                        </ListItemSecondaryAction>
                </ListItem>
                <Divider/>
              
                <ListItem button style={{paddingLeft:0,paddingRight:0}} onClick={() =>props.history.push(`${props.match.url}/body-images`,props.location.state)}>
                    <ListItemIcon>
                        <IconButton style={{borderRadius:"11px",background:"#F9FCFD"}}>
                        <Camera color="primary"/>
                        </IconButton>
                   
                    </ListItemIcon>
                    <ListItemText primary="Body images" />
                    <ListItemSecondaryAction>
                        <ArrowRight color="primary"/>
                        </ListItemSecondaryAction>
                </ListItem>

            </List>
            </Grid>
            <Grid item xs={12}>
            <div style={{marginTop: 10 }}>
   <UploadCard  files={props.Onboarding.bodyImages} sm Title={""} Icon={(cls)=><Camera color="primary" style={{fontSize:40}}/>}  handleUpdate={(files)=>props.updateOnboarding({bodyImages:files})} />
    </div>
            </Grid>
          </Grid>}
        </div>
      </Content>
      <Footer actionButton>
        <Button
          onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
