export default function Screen2(props) {
  const classes = useStyles();

  const createProgram = () => {
    if (props.editMode) {
      props.saveProgram({...props.ProgramDetails}).then((program) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program updated succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    
    } 
    
    
    else {
      props.createProgram(props.ProgramDetails).then((program) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program created succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    }
  };

  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Message</h2>
      
        <div className={classes.mainDiv}>

      
       <Grid container spacing={1} justify="center" alignItems="center">

      

 


  <Grid item xs={12}  >



<CustomInput
                
                
                multiline={true}
                bottomUnderline
                rows={4}
               
                formControlProps={{
                 
                  fullWidth: true
                }}
                inputProps={{
                 
                  value:props.ProgramDetails.GreetingMessage,
                  onChange:(e)=>props.updateProgram({GreetingMessage:e.target.value}),
                    multiline: true,
                    rows:4,
                  placeholder:"Write a breif message",
               
                }}
              />
            
</Grid>



 </Grid>
        </div>
      </Content>
      <Footer actionButton>

        <Button
      onClick={()=>{ props.history.goBack()}}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
          disabled={!props.ProgramDetails.GreetingMessage}
        
        >
           Done
        </Button>
 
      </Footer>
    </Container>
  );
}
