export default function SectionTabs(props) {
  const classes = useStyles();

  let id=uuidv4()
  return (
 
  
<div style={{backgroundColor:"#fff"}}>
  <input id={id} type="file" accept="image/x-png,image/gif,image/jpeg,image/png,image/jpg" onChange={(e)=>props.onUploadCover(e)} style={{display:"none"}}/>
      <List component="nav" aria-label="main mailbox folders">
        <ListItem button onClick={props.onRepeat}>
          <ListItemIcon>
            <Repeat className={classes.icon} />
          </ListItemIcon>
          <ListItemText primary="Repeat workout" classes={{primary: classes.primary}} />
        </ListItem>
        <Divider />
        <ListItem button>
          <ListItemIcon>
            <Camera className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Cover image" classes={{primary: classes.primary}} onClick={()=>document.getElementById(id).click()} />
        </ListItem>
        <Divider />
        <ListItem button onClick={()=>props.onEdit()}>
          <ListItemIcon>
            <Pencil className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Edit" classes={{primary: classes.primary}} />
        </ListItem>
        <Divider />
        <ListItem button>
          <ListItemIcon>
            <Delete className={classes.icon}/>
          </ListItemIcon>
          <ListItemText primary="Delete" classes={{primary: classes.primary}} />
        </ListItem>
       
      </List>
      {/* <Divider />
      <List component="nav" aria-label="secondary mailbox folders">
        <ListItem button>
          <ListItemText primary="Trash" />
        </ListItem>
        <ListItem href="#simple-list">
          <ListItemText primary="Spam" />
        </ListItem >
      </List> */}
    </div>
 





      
  );
}
