import React, { Component } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Search from "assets/svg/SearchHeart"
import HeartHealth from "assets/svg/HeartHealth"
import Muscle from "../../assets/svg/Muscle"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
    marginBottom: 5,
    marginTop:2,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    flexDirection: "column",
    justifyContent: "space-around",
    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 16,
    lineHeight: "18px",
    color:"#172A44",

  },
  secondary:{
      marginTop:8,
      color: "rgba(23,42,68)",
    fontWeight:"normal",
    fontSize: 14,
    lineHeight: "18px",
    
    /* or 129% */
    

  },
  icon:{
      fontSize:35,
      marginRight:30
  }
}));

export default function Screen2(props) {
  const classes = useStyles();

  return (
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>Account type</span>

        <div className={classes.mainDiv}>
         
          <div className={classes.child1}>
            <InsAthlete
          
              noBorder
              Title={"Athlete"}
              text={
                "As an athlete stay active by following the workouts made for you."
              }
              Icon={(cls) => <Athlete className={cls} />}
            />
          </div>
          <div className={classes.child2}>
          
      <ListItem>
        <ListItemAvatar>
        
            <Search className={classes.icon} />
       
        </ListItemAvatar>
        <ListItemText classes={{primary: classes.primary,secondary: classes.secondary}} primary="Find Program" secondary="Find a suitable program for your health goals. " />
      </ListItem>
      <ListItem>
        <ListItemAvatar>
        
            <HeartHealth className={classes.icon} />
       
        </ListItemAvatar>
        <ListItemText classes={{primary: classes.primary,secondary: classes.secondary}} primary="Stay active" secondary="View all your daily exercises video based." />
      </ListItem>
      <ListItem>
        <ListItemAvatar>
        
            <Muscle className={classes.icon}/>
        
        </ListItemAvatar>
        <ListItemText classes={{primary: classes.primary,secondary: classes.secondary}} primary="Achieve result" secondary="Get your results by completing your health program." />
      </ListItem>

          </div>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={()=>props.history.push("/onboarding/account-photo",props.location.state)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>
      </Footer>
    </Container>
  );
}
