import React, { Component,useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import {validateEmail,validatePassword,validatePhone} from "utils/validator"
import 'react-phone-input-2/lib/style.css'
import { FastfoodOutlined } from "@material-ui/icons";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
   color:"#172A44",
    marginBottom: 5,
    marginTop:2,

    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:"normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,

  },
  icon:{
      fontSize:45,
      marginRight:25
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [email,setEmail]=useState("")
  const [phone,setPhone]=useState("")

const updateEmail=(val=>{
  setEmail(val)
})





const onMobileNumberChange=(value, country, e, formattedValue)=>{


  setPhone(value+"")

}
const VerifyAccount=()=>{
    props.setData({uuid:props.data.type=="phone"?phone:email})
  props.updateFeedback({loading:true})
  if(props.data.type=="phone"){
    if(validatePhone(phone))
   { 
     axios.get(`${api.protocol}${api.baseUrl}${api.resetPasswordOtp}${phone}`).then((response)=>{
      props.updateFeedback({loading:false,snackbar:true,message:"Verification code sent to your mobile!",severity:"success"})
      props.history.push("/resetPassword/verify")
      
    }).catch((error)=>{
        if(error.response&&error.response.status===404)
      return props.updateFeedback({loading:false,snackbar:true,message:"Account does not exist with given phone number",severity:"error"})
    })
  }
  else{
    if(!validatePhone(phone))
    return props.updateFeedback({loading:false,snackbar:true,message:"Please enter a valid phone number!",severity:"warning"})
   
  }
    }
  
  else
  {
    if(validateEmail(email))
    {axios.post(`${api.protocol}${api.baseUrl}${api.ChangePasswordMail2}`,{email:email}).then((response)=>{
      
      props.updateFeedback({loading:false,snackbar:true,message:"Verification mail sent to your email!",severity:"success"})
      props.history.push("/resetPassword/verify")
    }).catch((error)=>{
        if(error.response&&error.response.status===404)
      return props.updateFeedback({loading:false,snackbar:true,message:"Account does not exist with given email",severity:"error"})
    })
  }
  else
  {
    if(!validateEmail(email))
    return props.updateFeedback({loading:false,snackbar:true,message:"Please enter a valid email!",severity:"warning"})
   
  }
    }
  }


  return (
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>{props.data.type=="email"?"Type your registered email":"Type your registered phone"}</span>
      
        <div className={classes.mainDiv}>
      
                     <div style={{width: "100%",paddingTop:10}}>
{props.data.type=="phone"?<CustomInput
mobile
                        labelText="Mobile number"
                        id="float"
                        placeholder="+91-88###-####"
                       
                       
                        onChange={onMobileNumberChange}
        inputProps={{ 
        value:phone,
          key:"1",
       }}
                        formControlProps={{
                          fullWidth: true
                        }}
                      />: 
                      <CustomInput
                  
                      labelText="Email address"
                      id="float-sd"
                      
      inputProps={{
       key:"email",
        value:email,
         placeholder:"xyz@abc.com",
       
                      onChange:(event)=>updateEmail(event.target.value)
    
    
    
    }}
                      formControlProps={{
                        fullWidth: true,
                        key:"3",
                      }}
                    />
                      
                      }
                     

                     </div>  
                 
                   
        </div>
      </Content>
      <Footer actionButton>
        <Button
    
        onClick={VerifyAccount}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>
      </Footer>
    </Container>
  );
}


