import React, { Component, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import {connect} from "react-redux"
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import TrackVisibility from 'react-visibility-sensor';
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import NotificationCard from "../../components/Card/notification";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import Earth from "assets/svg/Earth";
import Money from "assets/svg/Money";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import {updateProfile} from "store/actions/Profile"
import {fetchNotification,fetchCount,setVisible} from "store/actions/Notifications"
import moment from "moment"
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 22,
    marginBottom: 5,
    marginTop: 2,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    height: "100%",
    overflowY: "scroll",
    padding: 25,
    paddingTop: 10,

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 12,
    color: "#172A44",
    fontWeight: "normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
  },
  icon: {
    fontSize: 45,
    marginRight: 25,
  },
}));

function Screen2(props) {
  const classes = useStyles();
  useEffect(() => {
    console.log("fetchin not")
    fetchNotification()
    fetchCount()
  }, []);

const switchInstructor=(id)=>{
  props.updateProfile({type:"Athlete"}).then(()=>{
    setTimeout(()=> props.history.push(`/athlete/payment/${id}`),500)
    // props.history.push(`${props.match.path}/payment/${id}`)
  })

}

  return (
    <Container>
      <Header />

      <Content >
        <span className={classes.title}>Notifications</span>

        <div className={classes.mainDiv}>
{props.Notifications.map((item,index)=>{
  return (
    <>
     <React.Fragment key={index}>
    <TrackVisibility onChange={()=>!item.IsRead&&setVisible(item._id,index)} >
<NotificationCard
            Title={item.Sender.name}
            Text={`have Sent you a program`}
            details={item.SentProgramId}

            Time={moment(item.createdAt).startOf().fromNow()}
            avatar={item.Sender.profilePic}
            ButtonText={"View Program"}
            onClick={()=>switchInstructor(item.SentProgramId._id)}
          />
          </TrackVisibility>
           
                       </React.Fragment>

                       </>
  )
})}

          

       
        </div>
      </Content>
    </Container>
  );
}


export default connect(null,{updateProfile})(Screen2)