import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import {useState} from "react"
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";

import Button from "@material-ui/core/Button";
import Toolbar from "@material-ui/core/Toolbar";
import AppBar from "@material-ui/core/AppBar";
import IconButton from "@material-ui/core/IconButton";
import Drawer from "./DrawerInstructor";
import ArrowRight from "assets/svg/ArrowRight";
import { withRouter } from "react-router-dom";
import Typography from "@material-ui/core/Typography";
import {connect} from "react-redux"
import {signOut} from "store/actions/common"
const useStyles = makeStyles((theme) => ({
  root: {
    flexGrow: 1,
  },
  menuButton: {
    marginRight: theme.spacing(4),
  },
  title: {
    flexGrow: 1,
  },
}));
function SectionNavbars(props) {
  const [drawer,toggleDrawer]= React.useState(false)
  const classes = useStyles();
  console.log(props.history,"history")
  return (
    <>
    <GridContainer className={props.className}>
      <GridItem xs={12} sm={12} md={6}>
        <AppBar
          position={"fixed"}
          style={{ backgroundColor: "#fff", boxShadow: "none",...props.style }}
          {...props.navbarProps}
        >
          <Toolbar style={{paddingLeft:10,paddingRight:10}}>
            <IconButton
              className={classes.menuButton}
              color="inherit"
              aria-label="menu"
              onClick={()=>props.history.goBack()}
            >
              <ArrowRight
                color={"primary"}
                style={{ transform: "rotate(180deg)" }}
              />
            </IconButton>
            <Typography style={{ flexGrow: 1 }}></Typography>
            {props.button}
          </Toolbar>
        </AppBar>
      </GridItem>
    </GridContainer>
<Drawer
open={drawer}
toggleDrawer={toggleDrawer}
{...props}
/>
    </>
  );
}
const mapStateToProps =(state) =>{
  return{
    Profile: state.Profile
  }
}
export default connect(mapStateToProps, {signOut})(withRouter(SectionNavbars));
