import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import SelectType from "../Screens/createProgram/selectType"
import UploadBanner from "../Screens/createProgram/programBanners"
import Description from "../Screens/createProgram/programDescription"
import AddDays from "../Screens/createProgram/AddDays"
import AddExercise from "../Screens/createProgram/AddExercise"
import SelectExercise from "../Screens/createProgram/SelectExercise"
import CreateDiet from "../Screens/createProgram/CreateDiet"
import SetPayment from "../Screens/createProgram/setupPrice"
import SetDiscount from "../Screens/createProgram/setDiscount"
import Greeting from "../Screens/createProgram/greeting"
import Preview from "../Screens/createProgram/preview"
import ExerciseView from "../Screens/common/ExerciseView"
import ClientDetails from "../Screens/createProgram/ClientDetails"
import { MemoryRouter } from "react-router-dom";
import MessageScreen from "../Screens/createProgram/message"
import NavCreate from "../Screens/createProgram/NavCreate"
import {connect} from "react-redux"
import {
  
    createObject,
  
  } from "../store/actions/figgsLibrary";
import {updateProgram,createProgram,getSpecificProgram,saveProgram,getAllPrograms} from "../store/actions/createProgram"
import {updateFeedback} from "../store/actions/feedback"
import SelectUploadType from "../Screens/createProgram/SelectUploadType"
import FiggsLibrary from "./FiggsLibrary"
import {store} from "../store"
import ProgramList from 'store/reducers/ProgramList';
class CreateProgram extends Component {
    state={
currentWeek:0,
currentDay:0,
file:null,
fileObject:null,
currentExercise:0,
drawerState:false


    }


    componentDidMount=()=>{
        if(this.props.editMode){
        if( !this.props.ProgramDetails._id)
   { 
       store.dispatch({type:"SET_BUFFER",payload:this.props.ProgramDetails})
    }

    this.props.getSpecificProgram(this.props.ProgramList.editId).then(data =>{
      
      store.dispatch({ type:"INIT_PROGRAM",payload:data})
    })


        }


        if(this.props.ProgramDetails._id){
            store.dispatch({ type:"INIT_PROGRAM",payload:this.props.ProgramList.Buffer})
         
        }
      
    }

    componentWillMount=()=>{
        this.props.location.state={returnIndex:this.props.history.length}
    }

    componentWillUnmount() {
      
        if(this.props.ProgramDetails.Title)
        this.SaveAsDraft()
    }

    addWorkout=(data)=>{
        this.props
        .createObject({
          title: data.title,
          type: "file",
          parent:null,
          recent:true,
          file: { ...data, otherDetails: { ...data }, type: "exercise" },
        })
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise.push(data)
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }


    addExercises=(data,ret=-1)=>{
    //    console.log(ret)
    //     console.log(data,ret)
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise=[...program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise,...data]
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        if(ret<-1)
       this.props.history.go(ret)
        else
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }

    editExercise=(data)=>{
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]=data
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }

    ViewExercise=(index)=>{
        this.setState({currentExercise:index})
        this.props.history.push(`${this.props.match.url}/edit-exercise`)
    }

SaveAsDraft=()=>{
    if(!this.props.mode)
    {
      this.props.createProgram({...this.props.ProgramDetails,IsDraft:true,IsPublished:false}).then((program) => {

        this.props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Saved as Draft",
          severity: "info",
        });
       this.props.getAllPrograms()
      });
    }
}

    render() {
        console.log(this.props.location)
        return (
            <div>
               
                  
                   <Route exact  path={`${this.props.match.path}/`} render={()=><Description {...this.props}/>} />
                   {/* <Route exact  path={`${this.props.match.path}/`} render={()=><SelectType {...this.props} />} /> */}
                   <Route exact  path={`${this.props.match.path}/nav`} render={()=><NavCreate {...this.props}/>} />
                   <Route exact path={`${this.props.match.path}/exercise-view`} render={()=><ExerciseView {...this.props}  setState={(data)=>this.setState(data)} {...this.state}/>} />
                   <Route exact  path={`${this.props.match.path}/select-type`} render={()=><SelectUploadType {...this.props} setState={(data)=>this.setState(data)}/>} />
                   <Route exact  path={`${this.props.match.path}/upload-banner`} render={()=><UploadBanner {...this.props}/>} />
            <Route exact path={`${this.props.match.path}/clientDetails`} render={()=><ClientDetails {...this.props}/>}/>
                   <Route exact  path={`${this.props.match.path}/add-days`} render={()=><AddDays {...this.props} setState={(data)=>this.setState(data)} ViewExercise={this.ViewExercise} {...this.state}/>} />
                   <Route exact  path={`${this.props.match.path}/edit-exercise`} render={()=><AddExercise {...this.props} {...this.state} setState={(data)=>this.setState(data)} data={this.props.ProgramDetails.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]} editMode={true} editExercise={this.editExercise}/>}  />
                   <Route exact  path={`${this.props.match.path}/add-exercise`} render={()=><AddExercise {...this.props} file={this.state.file} setState={(data)=>this.setState(data)} fileObject={this.state.fileObject} handleWorkoutSuccess={this.addWorkout}/> } />
                   <Route exact  path={`${this.props.match.path}/create-diet`} render={()=><CreateDiet {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/select-exercise`} render={()=><SelectExercise {...this.props} />} />
                   <Route exact  path={`${this.props.match.path}/setup-payment`} render={()=><SetPayment {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/setup-discount`} render={()=><SetDiscount {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/overview`} render={()=><Greeting {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/confirmation`} render={()=><Preview  {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/message`} render={()=><MessageScreen {...this.props}/>} />
                   <Route    path={`${this.props.match.path}/library`} render={(props)=><FiggsLibrary {...props} return={props.location.state&&props.location.state.returnIndex?props.location.state.returnIndex:null} addExercises={this.addExercises} selectionMode />} />
                  
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
        ProgramDetails:state.NewProgram,
        Profile:state.Profile,
        ProgramList:state.ProgramList
    }
}

export default connect(mapStateToProps,{updateProgram,updateFeedback,createProgram,getSpecificProgram,getAllPrograms,saveProgram,  createObject,})(CreateProgram)