import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";


const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",
    height: "100%",
   fontFamily: "Proxima Nova",
    
border: "3px solid #E4F0F4",
boxSizing: "border-box",
borderRadius: "22px"
  },

  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    display:"flex",
    flexDirection:"column",
    alignItems:"center",
    justifyContent:"center",
    fontFamily: "Proxima Nova",
    
  },

 icon:{
fontSize: 80,
color: "rgba(23, 42, 68, 0.5)",
 },
  title:{ 
     
    color: "rgba(23, 42, 68, 0.5)",
      fontWeight:"bold",
      fontSize:24,
    marginTop:10,
      fontFamily: "Proxima Nova",
    },
    titleCollered:{ 
     
      color: "#172A44",
    
      },
  

    selected:{
        color:"#007EA0"
    },

    selectedContainer:{
        border: "2px solid #007EA0",
        background: "#E4F0F4"

    },
    noBorder:{
      border: "none"
    },

  subTitle:{
    fontWeight: "normal",
 
    fontSize: 14,
    lineHeight:"18px",
    alignItems:"center",
    fontFamily: "Proxima Nova",
    textAlign:"center",
    paddingTop:"8px",
    paddingLeft:"20px",
    paddingRight:"20px",
    color: "#172A44"
  }

}));

const TitleSub = React.forwardRef((props, ref) => {

const {
selected, 
Title, 
text, 
Icon,
noBorder,
onClick

}=props
  const classes = makeComponentStyles();


  const mainDiv=classNames({
    [classes.mainDiv]: true,
    [classes.selectedContainer]: selected,
    [classes.noBorder]: noBorder,
    

})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected,
[classes.titleCollered]:noBorder
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected,
        [classes.titleCollered]:noBorder
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  
      <div className={mainDiv} onClick={onClick}>
          <div className={classes.childDiv}>

          <span >
        {Icon(icon)}
          </span>
          <span className={title}>
            {Title}
          </span>
          <span
            className={subtitle}
          >
            {text}
          </span>

          </div>
  
        </div>



 
  );
});


export default TitleSub;
