function NumberFormatCustom(props) {
  const { inputRef, onChange, ...other } = props;

  return (
    <NumberFormat
      {...other}
      getInputRef={inputRef}
      onValueChange={(values) => {
        onChange({
          target: {
            name: props.name,
            value: values.value,
          },
        });
      }}
      thousandSeparator
      isNumericString
      prefix="$ "
    />
  );
}


export default function Screen2(props) {
  const classes = useStyles();
  const next=()=>{
   
      props.history.push(`${props.match.url}/setup-payment`,props.location.state)
    
  }

  const removeChip=(chip,index)=>{
     let Chips=[...props.ProgramDetails.SendTo]
    Chips.splice(index,1)
    props.updateProgram({SendTo:Chips})

  }

  const onAdd=(chip)=>{

    let Chips=[...props.ProgramDetails.SendTo]

    Chips.push(chip.toLowerCase())
    props.updateProgram({SendTo:Chips})
  }


  const onSkip=()=>{
    props.updateProgram({SendTo:[]})
    props.history.push(`${props.match.url}/setup-payment`,props.location.state)
  }

  return (
    <Container>
      <Header button={props.location.state&&props.location.state.mode=="edit"?"":<Button onClick={onSkip}>Skip</Button>} />

      <Content flex>
        <h2 className={classes.title}>Send client</h2>
      
        <div className={classes.mainDiv}>
       <Grid container spacing={2} justify="center" alignItems="center">

<Grid item xs={5}>
<div
            className={classes.banner}
            style={{
              backgroundImage: props.ProgramDetails.BannerImage
                ? `url(${props.ProgramDetails.BannerImage})`
                : `url(${require("assets/img/fitness.jpg")})`,
              backgroundSize: "cover",
            }}
          ></div>
{/* <img src={props.ProgramDetails.BannerImage}/> */}
</Grid>

<Grid item xs={7}>
  <div className={classes.programTitle}>{props.ProgramDetails.Title}</div>
</Grid>


   <Grid item xs={12} style={{marginTop:17}}>
        <div className={classes.label}>To</div>
       <ChipInput
       
       fullWidth
       value={props.ProgramDetails.SendTo?props.ProgramDetails.SendTo:[]}
       defaultValue={props.ProgramDetails.SendTo?props.ProgramDetails.SendTo:[]}
       onAdd={onAdd}
       onDelete={removeChip}
       InputProps={{
         placeholder:"(Optional) Email or figgs ID",
         style:{marginBottom:10}
       }}
       blurBehavior={"add"}
      
       
       
       
       />
         </Grid>







 </Grid>
        </div>
      </Content>
      <Footer actionButton>
    
        <Button
        onClick={next}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={props.ProgramDetails.SendTo.length==0}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>

      </Footer>
    </Container>
  );
}
