  const [selectedDate, setSelectedDate] = React.useState(new Date(props.Profile.DOB));
  const handleDateChange = (date) => {
    setSelectedDate(date);
    props.updateOnboarding({DOB:date})
  
  };


const email=props.Onboarding.email
const name=props.Onboarding.name
const authType=props.Onboarding.authType
const phone=props.Onboarding.phone
const DOB=props.Onboarding.DOB
 const changeName=(e)=>{
  props.updateOnboarding({name:e.target.value})
 }
const updateEmail=(val=>{
  props.updateOnboarding({email:val})
})

const updateMobile=(val=>{
  props.updateOnboarding({mobile:val})
})

const setAuth=(val=>{
  props.updateOnboarding({authType:val})
})

const updatePassword=(val=>{
  props.updateOnboarding({password:val})
})
const onMobileNumberChange=(e)=>{

console.log(e.target.value)
  props.updateOnboarding({phone:e.target.value})

}

const setMobileOrEmail=(e)=>{
  if(isPossiblePhoneNumber("+"+e.target.value))
{
  props.updateOnboarding({authType:0,phone:e.target.value})
}

if( validateEmail(e.target.value)){
  props.updateOnboarding({authType:1,email:e.target.value})
}
 

}


