import React, { Component, useState, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import IconButton from "@material-ui/core/IconButton";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import Camera from "assets/svg/Camera";
import AddVideo from "assets/svg/CamVid";
import Grid from "@material-ui/core/Grid";
import WeekCard from "components/Card/workout3";
import CustomTabs from "components/CustomTabs/CustomTabs2.js";
import UploadCard from "components/Card/UploadCard";
import AddIcon from "@material-ui/icons/Add";
import Drawer from "@material-ui/core/Drawer";
import InputBase from "@material-ui/core/InputBase";
import Toggle from "assets/svg/Toggle";
import Toggleh from "assets/svg/Toogleh";
import AppBar from "@material-ui/core/AppBar";
import Toolbar from "@material-ui/core/Toolbar";

import Typography from "@material-ui/core/Typography";
import EditDayExercise from "components/CreateProgram/ListDetails";
import EditWeeks from "components/CreateProgram/RepeatWeek";
import CustomInput from "components/CustomInput/CustomInput.js";
import InputAdornment from "@material-ui/core/InputAdornment";
import SearchIcon from "assets/svg/Search";
import Workout4 from "components/Card/workout4";
import Checkbox from "components/CheckBox";
import CollectionCard from "components/Card/CollectionCard.js";
import SpeedDial from "components/SpeedDial/speedDial";
import AddDialoge from "components/Dialogue/addFolder";
import FileActionSheet from "components/CreateProgram/FliggAction";
import MoreVertIcon from "@material-ui/icons/MoreVert";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 24,
    marginTop: 15,
    textTransform: "capitalize",
    marginBottom: 10,
  },
  mainDiv: {
    padding: 20,
    paddingTop: 10,

    paddingBottom: 80,
    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    padding: 5,
    fontWeight: "bold",
    color: "#172A44",
  },
  text: {
    fontFamily: "Proxima Nova",
    fontSize: "14px",
    padding: 5,
    marginBottom: 10,
    color: "#172A44",
  },

  drawer: {
    borderRadius: "26px 26px 0px 0px",
  },
  drawerInside: {
    padding: "30px 20px 20px 20px",
    position: "relative",
    height: "100%",
  },
  headDrawer: {
    display: "flex",
    flexDirection: "row",
    width: "100%",
    alignItems: "center",
    fontFamily: "Proxima Nova",
    fontSize: "18px",
    lineHeight: "29px",
    color: "#172A44",
  },

  icon: {
    fontSize: "16px",
  },
  input: {
    padding: "0px 0px 0px 0px",
    fontSize: "16px",
  },
  drawerContent: {
    marginTop: 20,
    width: "100%",
    height: "100%",
  },
  Exercise: {
    display: "flex",
    width: "100%",
    flexDirection: "row",
    justifyContent: "space-between",
  },
  moreIcon: {
    background: "rgba(0,0,0,0.1)",
    color: "white",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(1);
  const [collection, setCollection] = React.useState(null);
  const [drawer, toggleDrawer] = React.useState(false);
  const [modal, setFolderModal] = React.useState(false);
  const [itemData, setData] = React.useState({});
  const handleAddFolder = (data) => {
    props
      .createObject({
        title: data,
        type: "folder",
        parent: props.parent ? props.parent : null,
        ancestors: props.Library.ancestors,
      })
      .then(
        (res) => {
          setFolderModal(false);
        },
        () => {
          setFolderModal(false);
        }
      );
  };

  const handleFile = (e) => {
    let file = e.target.files[0];

    props.setState({ file: file });
    props.history.push(`${props.match.url}/action/add-exercise`,props.location.state);
  };
  const handleOpenFolder = (item) => {
    props.setState({ folderData: [...props.folderData, item.title] });
    props.fetchLibrary(item._id);
  };

  const back = () => {
    if (!props.Library.parent._id) {
      props.close();
      props.fetchLibrary(props.Library.parent.parent);
    } else {
      props.fetchLibrary(props.Library.parent.parent);
    }
  };

  const MoveItem = () => {
    props.updateLibrary({
       updateCondition: {_id:props.itemData._id} ,
       updateData:{ancestors:props.Library.ancestors,parent:props.Library.parent._id?props.Library.parent._id:null,recent:false}
      
      }).then(res=>{
        props.close();
        props.history.replace(`${props.match.url}${props.Library.parent._id?"/"+props.Library.parent._id:""}`,props.location.state)
      })
  };

  useEffect(() => {
    props.fetchLibrary(null);
  }, []); //
  return (
    <Container>
      <AppBar className={classes.appBar} position="static">
        <Toolbar>
          <IconButton
            edge="start"
            color="inherit"
            onClick={back}
            aria-label="close"
          >
            <ArrowRight style={{ transform: "rotate(180deg)" }} />
          </IconButton>
          <Typography variant="h6">Move to</Typography>
        </Toolbar>
      </AppBar>

      <Content>
        <input
          type="file"
          accept="video/*"
          onChange={handleFile}
          style={{ display: "none" }}
          id="filemangerupload"
        />

        <div className={classes.mainDiv}>
          <div className={classes.title}>
            {props.Library.parent.title ? props.Library.parent.title : null}
          </div>

          {value == 1 && collection == null && (
            <>
            <Grid container spacing={2} style={{ marginTop: 5 }}>
              {props.Library.children.map((item) => {
                return (
                  <>
                    {item.type != "file" ? (
                      <Grid item xs={6}>
                        <CollectionCard
                          title={item.title}
                          onClickMore={() => {
                            toggleDrawer(true);
                            setData(item);
                          }}
                          onClick={() => handleOpenFolder(item)}
                        />
                      </Grid>
                    ) : null}
                  </>
                );
              })}

              </Grid>
 {/* <Grid container spacing={2} style={{ marginTop: 5 }}>
              {props.Library.children.map((item) => {
                return (
                  <>
                    {item.type == "file" ? (
                      <Grid item xs={6}>
                        <Workout4
                        title2={"Exercise"}
                          sub1={item.title}
                          onClick={() => alert("zd")}
                          onClickMore={() => {
                            toggleDrawer(true);
                            setData(item);
                          }}
                          Icon={
                            <IconButton className={classes.moreIcon}>
                              <MoreVertIcon />
                            </IconButton>
                          }
                        
                        />
                      </Grid>
                    ) : null}
                  </>
                );
              })}
            </Grid> */}
            </>
          )}

          {value == 1 && collection !== null && (
            <div style={{ width: "100%" }}>
              <div className={classes.Exercise}>
                <span className={classes.title}>Full Body Exercise</span>
              </div>
              <CustomInput
                id="material"
                inputProps={{
                  style: { background: "#fafafa" },
                  placeholder: "Search for the instructor",
                  startAdornment: (
                    <InputAdornment position="start">
                   <SearchIcon style={{color: "rgba(23,42,68,0.3)"}} />
                    </InputAdornment>
                  ),
                }}
                formControlProps={{
                  fullWidth: true,
                }}
              />
              <Grid container spacing={2} style={{ marginTop: 5 }}>
                <Grid item xs={6}>
                  <Workout4
                    Icon={<Checkbox rounded={true} />}
                    sub1={"Squats"}
                  />
                </Grid>

                <Grid item xs={6}>
                  <Workout4
                    Icon={<Checkbox rounded={true} />}
                    sub1={"Squats"}
                  />
                </Grid>
              </Grid>
            </div>
          )}
        </div>

        <Drawer
          anchor={"bottom"}
          open={drawer}
          onClose={() => toggleDrawer(false)}
          className={classes.drawer}
          classes={{ paper: classes.drawer }}
        >
          <div className={classes.drawerInside}>
            <div className={classes.headDrawer}>
              <Button
                style={{ position: "absolute", right: 30, top: 20 }}
                onClick={() => toggleDrawer(false)}
              >
                Close
              </Button>
            </div>
            <div className={classes.drawerContent}>
              <FileActionSheet delete={() => props.deleteObject(itemData)} />
            </div>
          </div>
        </Drawer>

        <AddDialoge
          open={modal}
          handleClose={() => setFolderModal(false)}
          handleAdd={handleAddFolder}
        />
      </Content>

      <Footer actionButton>
        <Grid container spacing={2}>
          <Grid item xs={6}>
            <Button
              onClick={() => {props.close();props.history.replace(`${props.match.url}/${props.itemData.parent?props.itemData.parent:""}`,props.location.state)}}
              variant="outlined"
              fullWidth
              bold
            >
              Cancel
            </Button>
          </Grid>

          <Grid item xs={6}>
            <Button
              onClick={MoveItem}
              variant="contained"
              fullWidth
              bold
            >
              Move
            </Button>
          </Grid>
        </Grid>
      </Footer>
    </Container>
  );
}
