import React, { Component } from "react";
import { Router, Route, Switch } from "react-router-dom";
import Home from "../Screens/clienttabs/Home";
import ExerciseCalender from "../Screens/clienttabs/WorkoutCallender";
import Exercise from "../Screens/clienttabs/ExerciseView";
import MyPrograms from "../Screens/clienttabs/MyPrograms";
import Feedback from "../Screens/clienttabs/Feedback";
import Payment from "../Screens/clienttabs/Payments";
import Notification from "../Screens/clienttabs/Notification";
import { connect } from "react-redux";
import { getChatUsers } from "../store/actions/chat";

import Diet from "../Screens/clienttabs/DietPlan";
import ProgramDetails from "../Screens/clienttabs/ProgramDetails"
import { updateFeedback } from "../store/actions/feedback";
import {
  getClientPrograms,
  switchExercise,
  getOrder,
  updateStatus
} from "store/actions/clientExercise";
import { updateProgram, getAllPrograms } from "../store/actions/createProgram";
class CreateProgram extends Component {
  state = {
    currentWeek: 0,
    currentDay: 0,
    file: null,
    fileObject: null,
    tab: 0,
  };

  componentDidMount = () => {



    if (this.props.AtheletePlan.Exercises.orderId) {
      this.props.getOrder(this.props.AtheletePlan.Exercises.orderId);
    }
  };

  render() {
    return (
      <div>
        <Route
          exact
          path={`${this.props.match.path}/`}
          render={() => (
            <Home
              {...this.props}
              setState={(data) => this.setState(data)}
              tab={0}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/view/:val`}
          render={(props) => (
            <Home
              {...this.props}
              setState={(data) => this.setState(data)}
              tab={props.match.params.val}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/dietplan`}
          render={() => <Diet {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/exercise`}
          render={() => (
            <Exercise
              {...this.props}
              setState={(data) => this.setState(data)}
              {...this.state}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/exercise-calender`}
          render={() => (
            <ExerciseCalender
              {...this.props}
              setState={(data) => this.setState(data)}
              {...this.state}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/my-programs`}
          render={() => <MyPrograms {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/feedback`}
          render={() => <Feedback {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/notification`}
          render={() => <Notification {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/payment/:id`}
          render={(props) => (
            <Payment {...this.props} id={props.match.params.id} />
          )}
        />
         <Route
          exact
          path={`${this.props.match.path}/programDetails/:id`}
          render={(props) => (
            <ProgramDetails {...this.props} id={props.match.params.id} />
          )}
        />
      </div>
    );
  }
}

const mapStateToProps = (state) => {
  return {
    ProgramDetails: state.NewProgram,
    ProgramList: state.ProgramList,
    AtheletePlan: state.AtheletePlan,
    Notifications: state.Notifications.Notifications,
    Chat: state.Chat,
  };
};

export default connect(mapStateToProps, {
  updateProgram,
  getAllPrograms,
  getClientPrograms,
  switchExercise,
  getOrder,
  getChatUsers,
  updateFeedback,
  updateStatus
})(CreateProgram);
