import React from "react";
// nodejs library that concatenates classes
import classNames from "classnames";
// nodejs library to set properties for components
import PropTypes from "prop-types";

// material-ui components
import { makeStyles } from "@material-ui/core/styles";
import Tabs from "@material-ui/core/Tabs";
import Tab from "@material-ui/core/Tab";
import Icon from "@material-ui/core/Icon";
// core components
import CancelIcon from '@material-ui/icons/Cancel';
import Card from "components/Card/Card.js";
import CardBody from "components/Card/CardBody.js";
import CardHeader from "components/Card/CardHeader.js";
import Chip from '@material-ui/core/Chip';
import AddIcon from '@material-ui/icons/Add';
import styles from "assets/jss/material-kit-react/components/customTabsStyle.js";

const useStyles = makeStyles(styles);

export default function CustomTabs(props) {
  const [value, setValue] = React.useState(0);

  const hadleClick = (val) => {
    setValue(val);
  };
  const classes = useStyles();
  const { headerColor, plainTabs, tabs, title, rtlActive,weekTab } = props;
  const cardTitle = classNames({
    [classes.cardTitle]: true,
    [classes.cardTitleRTL]: rtlActive
  });

  


  const tabRoot=classNames({
    [classes.tabsRoot]: true,
    [classes.weekRoot]: weekTab
  })


  
  const root =classNames({
    [classes.tabRootButton]:true,
    [classes.weekTab]:weekTab

  })

  
  return (
    <div plain={plainTabs} style={{width:"100%"}} >
      <div color={"white"} plain={plainTabs} style={{width:"100%"}}>
        
        <Tabs
         
          {...props}
       
          
          classes={{
            root: tabRoot,
            indicator: classes.displayNone
          }}
        >
          {tabs.map((prop, key) => {
           
            return (
              <Chip
              classes={{
                root: root,
               colorSecondary: classes.colorSecondary,
               colorPrimary:classes.colorPrimary,
               deleteIcon:classes.deleteIcon,
               deleteIconColorSecondary:classes.deleteIconColorSecondary,
               clickableColorSecondary:classes.clickableColorSecondary
              }}
            color={props.selected===key?"primary":"default"}
            label={weekTab?"Week "+(key+1):prop}
               clickable	
              
               onClick={()=>props.hadleClick(key)}
               onDelete={props.deleteWeek?()=>props.deleteWeek(key):null}
             />
             
            );
          })}
           
            {!props.view&& <Chip
            classes={{
              root: root,
              label:classes.labelChip,
             colorSecondary: classes.colorSecondary,
             colorPrimary:classes.colorPrimary,
             deleteIcon:classes.deleteIcon,
             deleteIconColorSecondary:classes.deleteIconColorSecondary,
             clickableColorSecondary:classes.clickableColorSecondary
            }}
          color={"primary"}
             label="Add new week"
             icon={<AddIcon/>}
             clickable	
             onClick={()=>props.addWeek()}
            
           />}

          
        </Tabs>
      </div>
     
    </div>
  );
}

CustomTabs.propTypes = {
  headerColor: PropTypes.oneOf([
    "warning",
    "success",
    "danger",
    "info",
    "primary",
    "rose"
  ]),
  title: PropTypes.string,
  tabs: PropTypes.arrayOf(
    PropTypes.shape({
      tabName: PropTypes.string.isRequired,
      tabIcon: PropTypes.object,
      tabContent: PropTypes.node.isRequired
    })
  ),
  rtlActive: PropTypes.bool,
  plainTabs: PropTypes.bool
};
